                    initialDescription: activeWorkspace.description ?? "",
                  });
                }}
                title="Rename workspace"
                style={{
                  background: "transparent",
                  border: "1px solid var(--io-border)",
                  borderRadius: 6,
                  padding: "4px 10px",
                  cursor: "pointer",
                  fontSize: 12,
                  color: "var(--io-text-muted)",
                }}

