// Console module type definitions

import type { ChartConfig } from "../../shared/components/charts/chart-config-types";

export type PaneType =
  | "trend"
  | "point_table"
  | "alarm_list"
  | "graphic"
  | "blank";

export interface PaneConfig {
  id: string;
  type: PaneType;
  title?: string;
  /** When true, other panes cannot displace this pane during drag/resize. */
  pinned?: boolean;
  /** When true, the pane title bar is shown in live mode. Default absent = false (hidden). */
  showTitle?: boolean;
  // trend pane — legacy fields kept for backward compat, superseded by chartConfig
  trendPointIds?: string[];
  trendDuration?: number; // minutes, default 60
  /** Full chart configuration — replaces trendPointIds/trendDuration when present */
  chartConfig?: ChartConfig;
  /** When true, TrendPane opens Configure Chart on mount (set when dropped from palette). Cleared after first render. */
  promptConfig?: boolean;
  // point_table pane
  tablePointIds?: string[];
  // alarm_list pane
  alarmFilter?: "all" | "active" | "unacknowledged";
  // graphic pane
  graphicId?: string;
}

export type LayoutPreset =
  // Even grids
  | "1x1"
  | "2x1"
  | "1x2"
  | "2x2"
  | "3x1"
  | "1x3"
  | "3x2"
  | "2x3"
  | "3x3"
  | "4x1"
  | "1x4"
  | "4x2"
  | "2x4"
  | "4x3"
  | "3x4"
  | "4x4"
  // Asymmetric
  | "big-left-3-right"
  | "big-right-3-left"
  | "big-top-3-bottom"
  | "big-bottom-3-top"
  | "2-big-4-small"
  | "pip"
  | "featured-sidebar"
  | "side-by-side-unequal"
  // Legacy (keep for backwards compat)
  | "2x1+1";

/** One cell in the react-grid-layout 12-column coordinate system. `i` matches a PaneConfig.id. */
export interface GridItem {
  i: string;
  x: number;
  y: number;
  w: number;
  h: number;
}

export interface WorkspaceLayout {
  id: string;
  name: string;
  layout: LayoutPreset;
  panes: PaneConfig[];
  /** Free-form pane positions. When present, overrides the static `layout` preset for rendering. */
  gridItems?: GridItem[];
  /** Panes that no longer fit the current template are parked here, not deleted.
   *  When switching to a larger template, overflow panes fill the new empty slots in order. */
  overflowPanes?: PaneConfig[];
  /** Whether this workspace is published (visible to all users with console:read) */
  published?: boolean;
  /** ID of the user who owns this workspace */
  owner_id?: string;
  /** Optional user-provided description */
  description?: string;
  /** When true, the workspace is fully frozen: no drag, resize, pin, or × interactions. */
  locked?: boolean;
}

export interface ConsoleState {
  workspaces: WorkspaceLayout[];
  activeWorkspaceId: string | null;
}

              >
                Rename
              </button>

              {/* Publish toggle — gated by console:workspace_publish permission */}
              {canPublish && (
                <button
                  onClick={() =>
                    publishMutation.mutate({
                      id: activeWorkspace.id,
                      published: !activeWorkspace.published,
                    })
                  }
                  title={
                    activeWorkspace.published
                      ? "Unpublish workspace (visible to all users)"
                      : "Publish workspace (make visible to all users)"
                  }
                  style={{
                    background: activeWorkspace.published
                      ? "var(--io-accent-subtle)"
                      : "transparent",
                    border: "1px solid var(--io-border)",
                    borderRadius: 6,
                    padding: "4px 10px",
                    cursor: "pointer",
                    fontSize: 12,
                    color: activeWorkspace.published
                      ? "var(--io-accent)"
                      : "var(--io-text-muted)",
                    display: "flex",
                    alignItems: "center",
                    gap: 4,
                  }}
                >
                  {activeWorkspace.published ? "● Published" : "○ Publish"}
                </button>
              )}

              {/* Lock toggle button — replaces Edit/Done */}
              <button
                onClick={() => activeId && toggleLocked(activeId)}
                title={
                  isLocked
                    ? "Unlock workspace (enable drag/resize)"
                    : "Lock workspace (freeze layout)"
                }
                style={{
                  background: isLocked
                    ? "var(--io-accent-subtle)"
                    : "transparent",
                  border: "1px solid var(--io-border)",
                  borderRadius: 6,
                  padding: "4px 8px",
                  cursor: "pointer",
                  color: isLocked ? "var(--io-accent)" : "var(--io-text-muted)",
                  display: "flex",
                  alignItems: "center",
                  gap: 4,
                }}
              >
                <svg
                  width="13"
                  height="13"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                >
                  {isLocked ? (
                    <>
                      <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                      <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                    </>
                  ) : (
                    <>
                      <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                      <path d="M7 11V7a5 5 0 0 1 9.9-1" />
                    </>
                  )}
                </svg>
                {isLocked ? "Locked" : "Lock"}
              </button>
            </>
          )}

          {/* Delete workspace — always visible; grayed out when no workspace active */}
          <button
            onClick={activeWorkspace ? deleteActiveWorkspace : undefined}
            disabled={!activeWorkspace}
            title="Delete workspace"
            style={{
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 6,
              padding: "4px 10px",
              cursor: activeWorkspace ? "pointer" : "default",
              fontSize: 12,
              color: activeWorkspace
                ? "var(--io-danger)"
                : "var(--io-text-disabled)",
              opacity: activeWorkspace ? 1 : 0.4,
            }}
          >
            Delete
          </button>

          {/* Save / Save as Personal — always visible; grayed when no workspace; hidden when clean */}
          {!activeWorkspace ? (
            <button
              disabled
              title="Save workspace"
              style={{
                background: "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "4px 10px",
                cursor: "default",
                fontSize: 12,
                color: "var(--io-text-disabled)",
                opacity: 0.4,
              }}
            >
              Save
            </button>
          ) : (
            (() => {
              const wsSnap = serverSnapshotsRef.current[activeWorkspace.id];
              const wsIsDirty = wsSnap
                ? JSON.stringify(activeWorkspace) !== wsSnap
                : false;
              if (!wsIsDirty) return null;
              if (canSaveWorkspace(activeWorkspace)) {
                return (
                  <button
                    onClick={handleExplicitSave}
                    title="Save workspace (Ctrl+S)"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--io-border)",
                      borderRadius: 6,
                      padding: "4px 10px",
                      cursor: "pointer",
                      fontSize: 12,
                      color: "var(--io-accent)",
                    }}
                  >
                    Save
                  </button>
                );
              }
              if (canSaveAsPersonal(activeWorkspace)) {
                return (
                  <button
                    onClick={handleSaveAsPersonal}
                    title="Save a personal copy of this workspace"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--io-border)",
                      borderRadius: 6,
                      padding: "4px 10px",
                      cursor: "pointer",
                      fontSize: 12,
                      color: "var(--io-accent)",
                    }}
                  >
                    Save as Personal
                  </button>
                );
              }
              return null;
            })()
          )}

          {/* Aspect ratio toggle — always visible when a workspace is active */}
          {activeWorkspace && (
            <button
              onClick={() => setPreserveAspectRatio(!preserveAspectRatio)}
              title={
                preserveAspectRatio
                  ? "Preserve aspect ratio (click to stretch to fill pane)"
                  : "Stretch to fill pane (click to preserve aspect ratio)"
              }
              style={{
                background: preserveAspectRatio
                  ? "var(--io-accent)"
                  : "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "4px 8px",
                cursor: "pointer",
                fontSize: 12,
                color: preserveAspectRatio ? "#fff" : "var(--io-text-muted)",
                display: "flex",
                alignItems: "center",
                gap: 4,
              }}
            >
              {/* Lock/unlock icon */}
              {preserveAspectRatio ? (
                <svg
                  width="12"
                  height="12"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                >
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                </svg>
              ) : (
                <svg
                  width="12"
                  height="12"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                >
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0 1 9.9-1" />
                </svg>
              )}
              AR
            </button>
          )}

          {/* TT — hide-all pane titles toggle (spec MOD-CONSOLE-038 §4) */}
          {activeWorkspace && (
            <button
              onClick={() => setHideTitles(!hideTitles)}
              title={
                hideTitles
                  ? "Pane titles hidden (click to restore)"
                  : "Hide all pane titles"
              }
              style={{
                background: hideTitles ? "transparent" : "var(--io-accent)",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "4px 8px",
                cursor: "pointer",
                fontSize: 12,
                fontWeight: 600,
                color: hideTitles ? "var(--io-text-muted)" : "#fff",
              }}
            >
              TT
            </button>
          )}

          {/* Export split button — gated by console:export */}
          {activeWorkspace && canExport && (
            <div style={{ position: "relative", display: "inline-flex" }}>
              {/* Left: open full Export Dialog */}
              <button
                onClick={() => setExportDialogOpen(true)}
                title="Export workspace data"
                style={{
                  background: "transparent",
                  border: "1px solid var(--io-border)",
                  borderRight: "none",
                  borderRadius: "6px 0 0 6px",
                  padding: "5px 10px",
                  cursor: "pointer",
                  fontSize: 13,
                  color: "var(--io-text-primary)",
                  display: "flex",
                  alignItems: "center",
                  gap: 5,
                  whiteSpace: "nowrap",
                }}
              >
                Export
              </button>
              {/* Right: chevron opens quick-format dropdown */}
              <button
                onClick={() => setExportDropdownOpen((v) => !v)}
                title="Quick export format"
                style={{
                  background: "transparent",
                  border: "1px solid var(--io-border)",
                  borderRadius: "0 6px 6px 0",
                  padding: "5px 7px",
                  cursor: "pointer",
                  fontSize: 11,
                  color: "var(--io-text-primary)",
                  display: "flex",
                  alignItems: "center",
                }}
              >
                <svg
                  width="10"
                  height="10"
                  viewBox="0 0 10 10"
                  fill="currentColor"
                >
                  <polygon points="2,3 8,3 5,7" />
                </svg>
              </button>
              {exportDropdownOpen && (
                <>
                  <div
                    style={{ position: "fixed", inset: 0, zIndex: 999 }}
                    onClick={() => setExportDropdownOpen(false)}
                  />
                  <div
                    style={{
                      position: "absolute",
                      top: "100%",
                      right: 0,
                      zIndex: 1000,
                      background: "var(--io-surface-elevated)",
                      border: "1px solid var(--io-border)",
                      borderRadius: 6,
                      boxShadow: "0 8px 24px rgba(0,0,0,0.3)",
                      overflow: "hidden",
                      minWidth: 140,
                      marginTop: 4,
                    }}
                  >
                    {(
                      [
                        { label: "CSV", fmt: "csv" },
                        { label: "XLSX", fmt: "xlsx" },
                        { label: "JSON", fmt: "json" },
                        { label: "PDF", fmt: "pdf" },
                        { label: "Parquet", fmt: "parquet" },
                        { label: "HTML", fmt: "html" },
                      ] as { label: string; fmt: ExportFormat }[]
                    ).map(({ label, fmt }) => (
                      <button
                        key={fmt}
                        onClick={() => {
                          void handleExport(fmt);
                        }}
                        style={{
                          display: "block",
                          width: "100%",
                          padding: "8px 14px",
                          background: "none",
                          border: "none",
                          textAlign: "left",
                          cursor: "pointer",
                          fontSize: 13,
                          color: "var(--io-text-primary)",
                        }}
                        onMouseEnter={(e) => {
                          (
                            e.currentTarget as HTMLButtonElement
                          ).style.background = "var(--io-surface-secondary)";
                        }}
                        onMouseLeave={(e) => {
                          (
                            e.currentTarget as HTMLButtonElement
                          ).style.background = "none";
                        }}
                      >
                        {label}
                      </button>
                    ))}
                  </div>
                </>
              )}
              {/* Full Export Dialog */}
              <ExportDialog
                open={exportDialogOpen}
                onClose={() => setExportDialogOpen(false)}
                module="console"
                entity="workspace"
                filteredRowCount={(activeWorkspace.panes ?? []).reduce(
                  (n, p) => {
                    if (p.trendPointIds?.length)
                      return n + p.trendPointIds.length;
                    if (p.tablePointIds?.length)
                      return n + p.tablePointIds.length;
                    return n;
                  },
                  0,
                )}
                totalRowCount={(activeWorkspace.panes ?? []).reduce((n, p) => {
                  if (p.trendPointIds?.length)
                    return n + p.trendPointIds.length;
                  if (p.tablePointIds?.length)
                    return n + p.tablePointIds.length;
                  return n;
                }, 0)}
                availableColumns={[
                  { id: "tagname", label: "Tag Name" },
                  { id: "value", label: "Value" },
                  { id: "quality", label: "Quality" },
                  { id: "timestamp", label: "Timestamp" },
                  { id: "description", label: "Description" },
                  { id: "units", label: "Units" },
                ]}
                visibleColumns={["tagname", "value", "quality", "timestamp"]}
              />
            </div>
          )}

          {/* Close workspace */}
          {activeWorkspace && !isKiosk && (
            <button
              onClick={() => handleCloseWorkspace(activeWorkspace.id)}
              title="Close workspace"
              style={{
                background: "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "5px 8px",
                cursor: "pointer",
                color: "var(--io-text-muted)",
                display: "flex",
                alignItems: "center",
              }}
            >
              <svg
                width="13"
                height="13"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          )}

          {/* Publish toggle */}
          {activeWorkspace && canPublish && (
            <button
              onClick={() =>
                publishMutation.mutate({
                  id: activeWorkspace.id,
                  published: !activeWorkspace.published,
                })
              }
              title={
                activeWorkspace.published
                  ? "Unpublish workspace"
                  : "Publish workspace"
              }
              style={{
                background: activeWorkspace.published
                  ? "var(--io-accent-subtle)"
                  : "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "4px 10px",
                cursor: "pointer",
                fontSize: 12,
                color: activeWorkspace.published
                  ? "var(--io-accent)"
                  : "var(--io-text-muted)",
                display: "flex",
                alignItems: "center",
                gap: 4,
              }}
            >
              {activeWorkspace.published ? "● Published" : "○ Publish"}
            </button>
          )}

          {/* Open in New Window */}
          {activeWorkspace && !isKiosk && (
            <button
              onClick={() =>
                window.open(
                  `/detached/console/${activeWorkspace.id}`,
                  "_blank",
                  "noopener,noreferrer,width=1400,height=900",
                )
              }
              title="Open workspace in new window"
              style={{
                background: "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "5px 8px",
                cursor: "pointer",
                color: "var(--io-text-primary)",
                display: "flex",
                alignItems: "center",
              }}
            >
              <svg
                width="13"
                height="13"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6" />
                <polyline points="15 3 21 3 21 9" />
                <line x1="10" y1="14" x2="21" y2="3" />
              </svg>
            </button>
          )}

          {/* Browser fullscreen toggle — always visible when workspace active (spec §CX-CONSOLE-WORKSPACE-FULLSCREEN) */}
          {activeWorkspace && (
            <button
              onClick={toggleFullscreen}
              title={isFullscreen ? "Exit fullscreen" : "Enter fullscreen"}
              style={{
                background: "transparent",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "5px 8px",
                cursor: "pointer",
                color: "var(--io-text-primary)",
                display: "flex",
                alignItems: "center",
              }}
            >
              <svg
                width="13"
                height="13"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                {isFullscreen ? (
                  <path d="M8 3v3a2 2 0 0 1-2 2H3M21 8h-3a2 2 0 0 1-2-2V3M3 16h3a2 2 0 0 1 2 2v3M16 21v-3a2 2 0 0 1 2-2h3" />
                ) : (
                  <path d="M8 3H5a2 2 0 0 0-2 2v3M21 8V5a2 2 0 0 0-2-2h-3M3 16v3a2 2 0 0 0 2 2h3M16 21h3a2 2 0 0 0 2-2v-3" />
                )}
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Body */}
      <div
        style={{
          flex: 1,
          overflow: "hidden",
          display: "flex",
          flexDirection: "row",
        }}
      >
        {/* Left palette — hidden in kiosk mode so pane content fills the screen */}
        {!isKiosk && (
          <ConsolePalette
            visible={paletteVisible}
            onToggle={() => setPaletteVisible((v) => !v)}
            onQuickPlace={handleQuickPlace}
            workspaces={workspaces}
            activeWorkspaceId={activeId}
            onSelectWorkspace={(id) => {
              explicitlyClosedIdsRef.current.delete(id);
              saveClosedTabIds(explicitlyClosedIdsRef.current);
              if (!openTabIds.includes(id)) {
                setOpenTabIds((prev) => [...prev, id]);
              }
              setActiveId(id);
            }}
            onRenameWorkspace={(id) => {
              const ws = workspaces.find((w) => w.id === id);
              if (!ws) return;
              setNameModal({
                mode: "rename",
                workspaceId: id,
                initialName: ws.name,
                initialDescription: ws.description ?? "",
              });
            }}
            onDuplicateWorkspace={duplicateWorkspace}
            onDeleteWorkspace={(id) => {
              const target = workspaces.find((w) => w.id === id);
              if (target)
                setDeleteDialog({
                  workspaceId: id,
                  workspaceName: target.name,
                });
            }}
            panelWidth={panelWidth}
            onPanelResizeMouseDown={onPanelResizeMouseDown}
            isPanelResizing={isPanelResizing}
          />
        )}

        {/* Workspace area */}
        <div
          style={{
            flex: 1,
            overflow: "hidden",
            display: "flex",
            flexDirection: "column",
            minHeight: 0,
          }}
        >
          {/* Swap mode banner */}
          {swapModeSourceId && (
            <div
              style={{
                flexShrink: 0,
                padding: "6px 14px",
                background: "var(--io-warning)",
                color: "var(--io-text-inverse)",
                fontSize: 12,
                display: "flex",
                alignItems: "center",
                gap: 10,
              }}
            >
              <svg
                width="13"
                height="13"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <path d="M7 16V4m0 0L3 8m4-4l4 4M17 8v12m0 0l4-4m-4 4l-4-4" />
              </svg>
              Click another pane to swap positions — press Escape to cancel
              <button
                onClick={() => setSwapModeSourceId(null)}
                style={{
                  marginLeft: "auto",
                  background: "none",
                  border: "none",
                  color: "var(--io-text-inverse)",
                  cursor: "pointer",
                  fontSize: 11,
                }}
              >
                Cancel
              </button>
            </div>
          )}
          {/* Auto-save failure banner — persistent until manually retried or save succeeds */}
          {showSaveBanner && (
            <div
              style={{
                flexShrink: 0,
                padding: "6px 14px",
                background: "var(--io-alarm-high)",
                color: "#fff",
                fontSize: 13,
                display: "flex",
                alignItems: "center",
                gap: 12,
              }}
            >
              <span>Workspace changes not saved</span>
              <button
                onClick={() => {
                  if (activeWorkspace) {
                    saveFailCountRef.current = 0;
                    setShowSaveBanner(false);
                    saveMutation.mutate(activeWorkspace);
                  }
                }}
                style={{
                  background: "rgba(0,0,0,0.25)",
                  border: "1px solid rgba(255,255,255,0.4)",
                  borderRadius: 4,
                  color: "#fff",
                  padding: "2px 10px",
                  cursor: "pointer",
                  fontSize: 12,
                }}
              >
                Save now
              </button>
            </div>
          )}

          {workspaces.length === 0 || openTabIds.length === 0 ? (
            /* Empty state */
            <div
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                gap: 16,
                color: "var(--io-text-muted)",
              }}
            >
              <svg
                width="56"
                height="56"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1"
              >
                <rect x="2" y="3" width="20" height="14" rx="2" />
                <line x1="12" y1="3" x2="12" y2="17" />
                <line x1="2" y1="10" x2="22" y2="10" />
                <line x1="8" y1="21" x2="16" y2="21" />
                <line x1="12" y1="17" x2="12" y2="21" />
              </svg>
              <div style={{ textAlign: "center", fontSize: 15 }}>
                <p
                  style={{
                    margin: "0 0 4px",
                    fontWeight: 600,
                    color: "var(--io-text-primary)",
                  }}
                >
                  {workspaces.length === 0
                    ? "No workspaces yet"
                    : "No open workspaces"}
                </p>
                <p style={{ margin: 0, fontSize: 13 }}>
                  {workspaces.length === 0
                    ? "Create your first workspace to start monitoring"
                    : "Open one from the palette, or create a new one"}
                </p>
              </div>
              <button
                onClick={createWorkspace}
                style={{
                  background: "var(--io-accent)",
                  color: "#fff",
                  border: "none",
                  borderRadius: 6,
                  padding: "9px 20px",
                  cursor: "pointer",
                  fontSize: 14,
                  fontWeight: 600,
                }}
              >
                Create Workspace
              </button>
            </div>
          ) : activeWorkspace ? (
            <WorkspaceGrid
              workspace={activeWorkspace}
              locked={isLocked}
              pinnedIds={pinnedIds}
              selectedPaneIds={selectedPaneIds}
              preserveAspectRatio={preserveAspectRatio}
              hideTitles={hideTitles}
              onConfigurePane={handleConfigurePane}
              onRemovePane={handleRemovePane}
              onSelectPane={handlePaneSelect}
              onSelectManyPanes={handlePaneSelectMany}
              onPaletteDrop={handlePaletteDrop}
              onGridBackgroundDrop={handleDropAdd}
              onGridLayoutChange={handleGridLayoutChange}
              onWorkspaceContextMenu={handleWorkspaceContextMenu}
              swapModeSourceId={swapModeSourceId}
              onSwapWith={handleSwapWith}
              onSwapComplete={handleSwapComplete}
              onReplace={handleReplacePane}
              onPinToggle={handlePinToggle}
              onBrowserFullscreen={toggleFullscreen}
            />
          ) : (
            <div
              style={{
                flex: 1,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: "var(--io-text-muted)",
                fontSize: 14,
              }}
            >
              Select a workspace above
            </div>
          )}

          {/* Historical Playback Bar — only shown in historical mode */}
          {workspaces.length > 0 && isHistorical && (
            <HistoricalPlaybackBar
              module="console"
              graphicId={activeId ?? ""}
              resolveExportGraphicId={async () => {
                const { workspaces: ws, activeId: aid } =
                  useWorkspaceStore.getState();
                const live = ws.find((w) => w.id === aid);
                if (!live) throw new Error("No active workspace to export");
                const result = await consoleApi.saveWorkspaceSnapshot({
                  name: `[export] ${live.name}`,
                  layout: live.layout,
                  panes: live.panes,
                  gridItems: live.gridItems,
                  overflowPanes: live.overflowPanes,
                  published: false,
                  description: live.description,
                });
                if (!result.success)
                  throw new Error("Failed to save workspace snapshot");
                return result.data.id;
              }}
            />
          )}

          {/* Status bar */}
          {workspaces.length > 0 && (
            <ConsoleStatusBar workspaceName={activeWorkspace?.name ?? ""} />
          )}
        </div>
      </div>

      {/* Pane config modal */}
      {configuringPane && (
        <PaneConfigModal
          pane={configuringPane}
          onSave={handleSavePane}
          onClose={() => setConfiguringPaneId(null)}
        />
      )}

      {/* Workspace background right-click menu (§14.1) */}
      {workspaceBgCtxMenu && (
        <ContextMenu
          x={workspaceBgCtxMenu.x}
          y={workspaceBgCtxMenu.y}
          onClose={() => setWorkspaceBgCtxMenu(null)}
          items={[
            {
              label: "Add Pane",
              onClick: () => {
                if (activeId) {
                  updateWorkspace(activeId, (w) => {
                    const newId = `pane-${Date.now()}`;
                    const currentItems = w.gridItems?.length
                      ? w.gridItems
                      : presetToGridItems(w.layout, w.panes);
                    const halfW = Math.round(GRID_COLS / 2);
                    const halfH = Math.round(GRID_ROWS / 2);
                    const freeSlot = findFreeSlot(currentItems, halfW, halfH);
                    let newGridItems: GridItem[];
                    if (freeSlot) {
                      newGridItems = [
                        ...currentItems,
                        { i: newId, ...freeSlot },
                      ];
                    } else {
                      const tentative = {
                        i: newId,
                        x: 0,
                        y: 0,
                        w: halfW,
                        h: halfH,
                      };
                      const pinnedSet = new Set(
                        w.panes.filter((p) => p.pinned).map((p) => p.id),
                      );
                      newGridItems = scanLineCompact(
                        [...currentItems, tentative],
                        tentative.i,
                        pinnedSet,
                        currentItems,
                      );
                    }
                    return {
                      ...w,
                      panes: [
                        ...w.panes,
                        { id: newId, type: "blank" as const },
                      ],
                      gridItems: newGridItems,
                    };
                  });
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  if (ws) persistWorkspace(ws);
                }
                setWorkspaceBgCtxMenu(null);
              },
            },
            {
              label: "Paste",
              disabled: copiedPanesRef.current.length === 0,
              onClick: () => {
                if (activeId && copiedPanesRef.current.length > 0) {
                  const pasted = copiedPanesRef.current.map((p) => ({
                    ...p,
                    id: `pane-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
                  }));
                  updateWorkspace(activeId, (w) => ({
                    ...w,
                    panes: [...w.panes, ...pasted],
                  }));
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  if (ws) persistWorkspace(ws);
                }
                setWorkspaceBgCtxMenu(null);
              },
            },
            {
              label: "Select All",
              onClick: () => {
                if (activeId) {
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  if (ws) selectAll(ws.panes.map((p) => p.id));
                }
                setWorkspaceBgCtxMenu(null);
              },
            },
            {
              label: "Clear Grid",
              divider: true,
              onClick: () => {
                if (activeId) {
                  updateWorkspace(activeId, (w) => ({ ...w, panes: [] }));
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  if (ws) persistWorkspace(ws);
                }
                setWorkspaceBgCtxMenu(null);
              },
            },
            {
              label: "Workspace Properties…",
              onClick: () => {
                setWorkspaceBgCtxMenu(null);
                if (activeId) {
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  setNameModal({
                    mode: "rename",
                    workspaceId: activeId,
                    initialName: ws?.name ?? "",
                    initialDescription: ws?.description ?? "",
                  });
                }
              },
            },
            {
              label: "Version History",
              onClick: () => {
                setWorkspaceBgCtxMenu(null);
                if (activeId) setVersionHistoryWorkspaceId(activeId);
              },
            },
            {
              label: "Save and Close",
              onClick: () => {
                setWorkspaceBgCtxMenu(null);
                if (activeId) handleCloseWorkspace(activeId);
              },
            },
            {
              label: "Delete…",
              divider: true,
              onClick: () => {
                setWorkspaceBgCtxMenu(null);
                if (activeId) {
                  const ws = useWorkspaceStore
                    .getState()
                    .workspaces.find((w) => w.id === activeId);
                  if (ws)
                    setDeleteDialog({
                      workspaceId: activeId,
                      workspaceName: ws.name,
                    });
                }
              },
            },
          ]}
        />
      )}

      {/* Workspace name modal (create & rename) */}
      {nameModal && (
        <WorkspaceNameModal
          mode={nameModal.mode}
          initialName={nameModal.initialName}
          initialDescription={nameModal.initialDescription ?? ""}
          onConfirm={(name, description) => {
            if (nameModal.mode === "create") {
              confirmCreateWorkspace(name, description);
            } else if (nameModal.workspaceId) {
              handleRenameWorkspace(nameModal.workspaceId, name, description);
              setNameModal(null);
            }
          }}
          onCancel={() => setNameModal(null)}
        />
      )}

      {/* Close-without-save confirmation dialog */}
      {closeDialog && (
        <CloseConfirmDialog
          workspaceName={closeDialog.workspaceName}
          onSave={() => handleSaveAndClose(closeDialog.workspaceId)}
          onDiscard={() => handleDiscardAndClose(closeDialog.workspaceId)}
          onCancel={() => setCloseDialog(null)}
        />
      )}

      {/* Delete confirmation dialog */}
      {deleteDialog && (
        <DeleteConfirmDialog
          workspaceName={deleteDialog.workspaceName}
          onConfirm={() => confirmDeleteWorkspace(deleteDialog.workspaceId)}
          onCancel={() => setDeleteDialog(null)}
        />
      )}

      {/* Workspace tab context menu */}
      {tabContextMenu &&
        (() => {
          const ws = workspaces.find(
            (w) => w.id === tabContextMenu.workspaceId,
          );
          if (!ws) return null;
          return (
            <ContextMenu
              x={tabContextMenu.x}
              y={tabContextMenu.y}
              onClose={() => setTabContextMenu(null)}
              items={[
                {
                  label: "Switch to Workspace",
                  onClick: () => setActiveId(ws.id),
                },
                {
                  label: "Open in New Window",
                  onClick: () => {
                    window.open(
                      `/detached/console/${ws.id}`,
                      "_blank",
                      "noopener,noreferrer,width=1400,height=900",
                    );
                    setTabContextMenu(null);
                  },
                },
                {
                  label: isFavorite(ws.id)
                    ? "Remove from Favorites"
                    : "Add to Favorites",
                  onClick: () => {
                    toggleFavorite(ws.id);
                    setTabContextMenu(null);
                  },
                },
                {
                  label: "Rename…",
                  divider: false,
                  onClick: () => {
                    setNameModal({
                      mode: "rename",
                      workspaceId: ws.id,
                      initialName: ws.name,
                    });
                    setTabContextMenu(null);
                  },
                },
                {
                  label: "Duplicate",
                  onClick: () => duplicateWorkspace(ws.id),
                },
                {
                  label: "Version History",
                  onClick: () => {
                    setVersionHistoryWorkspaceId(ws.id);
                    setTabContextMenu(null);
                  },
                },
                {
                  label: ws.locked ? "Unlock Workspace" : "Lock Workspace",
                  divider: true,
                  onClick: () => {
                    toggleLocked(ws.id);
                    setTabContextMenu(null);
                  },
                },
                {
                  label: "Save and Close",
                  onClick: () => {
                    setTabContextMenu(null);
                    handleCloseWorkspace(ws.id);
                  },
                },
                ...(canPublish
                  ? [
                      {
                        label: ws.published ? "Unpublish" : "Publish",
                        divider: false,
                        onClick: () =>
                          publishMutation.mutate({
                            id: ws.id,
                            published: !ws.published,
                          }),
                      },
                    ]
                  : []),
                {
                  label: "Delete…",
                  divider: true,
                  onClick: () => {
                    setTabContextMenu(null);
                    setDeleteDialog({
                      workspaceId: ws.id,
                      workspaceName: ws.name,
                    });
                  },
                },
              ]}
            />
          );
        })()}

      {versionHistoryWorkspaceId && (
        <VersionRecoveryDialog
          open={!!versionHistoryWorkspaceId}
          onClose={() => setVersionHistoryWorkspaceId(null)}
          objectType="workspace"
          objectId={versionHistoryWorkspaceId}
          objectName={workspaces.find((w) => w.id === versionHistoryWorkspaceId)?.name}
          onLoadVersion={handleLoadWorkspaceVersion}
        />
      )}

      <SaveConfirmDialog
        open={showSaveConfirmDialog}
        onOpenChange={setShowSaveConfirmDialog}
        objectName={workspaces.find((w) => w.id === activeId)?.name}
        onConfirm={({ label }) => {
          setShowSaveConfirmDialog(false);
          const ws = useWorkspaceStore
            .getState()
            .workspaces.find((w) => w.id === activeId);
          if (ws) persistWorkspace(ws, label);
        }}
      />
    </div>
  );
}

// ---------------------------------------------------------------------------
// WorkspaceNameModal — used for both create and rename flows
// ---------------------------------------------------------------------------

function WorkspaceNameModal({
  mode,
  initialName,
  initialDescription = "",
  onConfirm,
  onCancel,
}: {
  mode: "create" | "rename";
  initialName: string;
  initialDescription?: string;
  onConfirm: (name: string, description: string) => void;
  onCancel: () => void;
}) {
  const [name, setName] = useState(initialName);
  const [description, setDescription] = useState(initialDescription);

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter" && name.trim())
      onConfirm(name.trim(), description.trim());
    if (e.key === "Escape") onCancel();
  }

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <div
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: 8,
          padding: "20px 24px",
          minWidth: 360,
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        <div style={{ fontSize: 14, fontWeight: 600, color: "var(--io-text)" }}>
          {mode === "create" ? "New Workspace" : "Rename Workspace"}
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <label
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              fontWeight: 500,
            }}
          >
            Name
          </label>
          <input
            autoFocus
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Workspace name"
            style={{
              padding: "6px 10px",
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text)",
              fontSize: 13,
              outline: "none",
            }}
          />
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <label
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              fontWeight: 500,
            }}
          >
            Description <span style={{ fontWeight: 400 }}>(optional)</span>
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Escape") onCancel();
            }}
            placeholder="Brief description of this workspace"
            rows={3}
            style={{
              padding: "6px 10px",
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text)",
              fontSize: 13,
              outline: "none",
              resize: "vertical",
              fontFamily: "inherit",
            }}
          />
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            style={{
              padding: "5px 14px",
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text-muted)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            onClick={() => {
              if (name.trim()) onConfirm(name.trim(), description.trim());
            }}
            disabled={!name.trim()}
            style={{
              padding: "5px 14px",
              background: "var(--io-accent)",
              border: "none",
              borderRadius: 4,
              color: "#fff",
              fontSize: 12,
              cursor: name.trim() ? "pointer" : "not-allowed",
              opacity: name.trim() ? 1 : 0.5,
            }}
          >
            {mode === "create" ? "Create" : "Rename"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// DeleteConfirmDialog — confirm before permanently deleting a workspace
// ---------------------------------------------------------------------------

function DeleteConfirmDialog({
  workspaceName,
  onConfirm,
  onCancel,
}: {
  workspaceName: string;
  onConfirm: () => void;
  onCancel: () => void;
}) {
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <div
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: 8,
          padding: "20px 24px",
          minWidth: 340,
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        <div style={{ fontSize: 14, fontWeight: 600, color: "var(--io-text)" }}>
          Delete workspace?
        </div>
        <div
          style={{
            fontSize: 13,
            color: "var(--io-text-muted)",
            lineHeight: 1.5,
          }}
        >
          <strong style={{ color: "var(--io-text)" }}>{workspaceName}</strong>{" "}
          will be permanently deleted. This cannot be undone.
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            style={{
              padding: "5px 14px",
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text-muted)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            onClick={onConfirm}
            style={{
              padding: "5px 14px",
              background: "var(--io-danger)",
              border: "none",
              borderRadius: 4,
              color: "#fff",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Delete
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// CloseConfirmDialog — save / discard / cancel when closing with unsaved changes
// ---------------------------------------------------------------------------

function CloseConfirmDialog({
  workspaceName,
  onSave,
  onDiscard,
  onCancel,
}: {
  workspaceName: string;
  onSave: () => void;
  onDiscard: () => void;
  onCancel: () => void;
}) {
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <div
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: 8,
          padding: "20px 24px",
          minWidth: 340,
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        <div style={{ fontSize: 14, fontWeight: 600, color: "var(--io-text)" }}>
          Unsaved changes
        </div>
        <div
          style={{
            fontSize: 13,
            color: "var(--io-text-muted)",
            lineHeight: 1.5,
          }}
        >
          <strong style={{ color: "var(--io-text)" }}>{workspaceName}</strong>{" "}
          has unsaved changes. Save before closing?
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            style={{
              padding: "5px 14px",
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text-muted)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            onClick={onDiscard}
            style={{
              padding: "5px 14px",
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text-muted)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Discard
          </button>
          <button
            onClick={onSave}
            style={{
              padding: "5px 14px",
              background: "var(--io-accent)",
              border: "none",
              borderRadius: 4,
              color: "#fff",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Save
          </button>
        </div>
      </div>
    </div>
  );
}

content.content:
1	import React, {
2	  useRef,
3	  useEffect,
4	  useState,
5	  useCallback,
6	  useMemo,
7	} from "react";
8	import { createPortal } from "react-dom";
9	import { GridLayout, noCompactor, type LayoutItem } from "react-grid-layout";
10	import "react-grid-layout/css/styles.css";
11	import "react-resizable/css/styles.css";
12	import "./WorkspaceGrid.css";
13	import PaneWrapper from "./PaneWrapper";
14	import { ErrorBoundary } from "../../shared/components/ErrorBoundary";
15	import { CONSOLE_DRAG_KEY, type ConsoleDragItem } from "./ConsolePalette";
16	import type { WorkspaceLayout, PaneConfig, GridItem } from "./types";
17	import {
18	  GRID_COLS,
19	  GRID_ROWS,
20	  MIN_W,
21	  MIN_H,
22	  presetToGridItems,
23	  scanLineCompact,
