28	// ---------------------------------------------------------------------------
29	// gridCompactor — noCompactor with allowOverlap:true
30	// ---------------------------------------------------------------------------
31	//
32	// RGL's noCompactor (type:null, allowOverlap:false) has a special branch in
33	// moveElementAwayFromCollision that fires when compactType===null and there is
34	// a north collision during a user action. It swaps the y positions of the two
35	// items, causing the pane to teleport to y=0 mid-drag and the neighbour to get
36	// pushed far down. This only manifests for north/NW/NE resize because those are
37	// the only handles that move the item's y position during the drag.
38	//
39	// Setting allowOverlap:true makes moveElement return early (cloneLayout) when
40	// collisions are detected, so items can overlap during the interaction. Our
41	// handleResizeStop / handleDragStop already call resolveCollisions to clean up
42	// at the end of every gesture — allowOverlap here just keeps the mid-drag
43	// frames clean.
44	
45	const gridCompactor = { ...noCompactor, allowOverlap: true };
