291	  const handleDrag = useCallback(
292	    (
293	      _layout: readonly LayoutItem[],
294	      _old: LayoutItem | null,
295	      newItem: LayoutItem | null,
296	    ) => {
297	      if (!newItem) return;
298	      gestureIdRef.current = newItem.i;
299	      const withNewPos = gridItemsRef.current.map(
