312	        scanLineCompact(
313	          withNewPos,
314	          newItem.i,
315	          pinnedIds,
316	          preGestureLayoutRef.current,
317	          GRID_COLS,
318	          GRID_ROWS,
319	        ),
320	      );
321	    },
322	    [pinnedIds],
323	  );
