325	  const handleResize = useCallback(
326	    (
327	      _layout: readonly LayoutItem[],
328	      _old: LayoutItem | null,
329	      newItem: LayoutItem | null,
330	    ) => {
331	      if (!newItem) return;
332	      gestureIdRef.current = newItem.i;
333	      const withNewSize = gridItemsRef.current.map(
334	        (item): GridItem =>
335	          item.i === newItem.i
336	            ? {
337	                i: item.i,
338	                x: newItem.x,
339	                y: newItem.y,
340	                w: newItem.w,
341	                h: newItem.h,
342	              }
343	            : item,
344	      );
345	      setPreviewLayout(
346	        scanLineCompact(
347	          withNewSize,
348	          newItem.i,
349	          pinnedIds,
350	          preGestureLayoutRef.current,
351	          GRID_COLS,
352	          GRID_ROWS,
353	        ),
354	      );
355	    },
356	    [pinnedIds],
357	  );
358	
359	  const handleResizeStart = useCallback(
360	    (
361	      _layout: readonly LayoutItem[],
362	      _oldItem: LayoutItem | null,
363	      newItem: LayoutItem | null,
364	    ) => {
365	      isResizingRef.current = true;
366	      preGestureLayoutRef.current = gridItemsRef.current.map((it) => ({
367	        ...it,
368	      }));
369	      if (newItem) {
370	        resizeStartRef.current = {
371	          i: newItem.i,
372	          x: newItem.x,
373	          y: newItem.y,
374	          w: newItem.w,
375	          h: newItem.h,
376	        };
377	      }
378	    },
379	    [],
380	  );
