401	  // ── Resize stop — scan-line compaction ───────────────────────────────────
402	
403	  const handleResizeStop = useCallback(
404	    (
405	      _layout: readonly LayoutItem[],
406	      _oldItem: LayoutItem | null,
407	      newItem: LayoutItem | null,
408	    ) => {
409	      // Keep isResizingRef true until the next animation frame — RGL calls
410	      // onLayoutChange(finalLayout) synchronously after this handler returns,
411	      // and we need handleLayoutChange to ignore that unresolved layout.
412	      requestAnimationFrame(() => {
413	        isResizingRef.current = false;
414	      });
415	      setPreviewLayout(null);
416	      gestureIdRef.current = null;
417	      const preGesture = preGestureLayoutRef.current;
418	      preGestureLayoutRef.current = null;
419	      const startDims = resizeStartRef.current;
420	      resizeStartRef.current = null;
421	
422	      if (locked || !onGridLayoutChange || !newItem) return;
423	
424	      let finalW = newItem.w;
425	      let finalH = newItem.h;
