427	      // Shift+corner: lock to starting grid-unit aspect ratio.
428	      // Only fires when both w and h changed (corner handle), not side handles.
429	      if (
430	        shiftKeyRef.current &&
431	        startDims?.i === newItem.i &&
432	        newItem.w !== startDims.w &&
433	        newItem.h !== startDims.h
