466	  // ── Drag stop — scan-line compaction ─────────────────────────────────────
467	
468	  const handleDragStop = useCallback(
469	    (
470	      _layout: readonly LayoutItem[],
471	      _oldItem: LayoutItem | null,
472	      newItem: LayoutItem | null,
473	    ) => {
