558	  const handleGridPointerDown = useCallback(
559	    (e: React.PointerEvent<HTMLDivElement>) => {
560	      if (locked || !onSelectPane) return;
561	      if (!e.isPrimary || e.button !== 0) return;
562	      // Ignore any pointerdown that arrives while the button is already held.
563	      if (isPointerDownRef.current) return;
564	      if (boxStartRef.current) return;
