632	  const handleGridPointerUp = useCallback(
633	    (e: React.PointerEvent<HTMLDivElement>) => {
634	      if (!e.isPrimary) return;
635	      // Always clear button-state at the top, before any early returns.
636	      isPointerDownRef.current = false;
637	      hasCaptureRef.current = false;
638	      const startedInContent = startedInPaneContentRef.current;
639	      startedInPaneContentRef.current = false;
640	      if (startedInContent) {
641	        boxStartRef.current = null;
642	        boxRectRef.current = null;
643	        setBoxRect(null);
644	        return;
645	      }
646	      // Read from ref — never from the React state closure which may be stale
647	      // if React deferred the commit of the last setBoxRect call.
648	      const br = boxRectRef.current;
649	      if (!boxStartRef.current || !br || !onSelectPane) {
650	        boxStartRef.current = null;
651	        boxRectRef.current = null;
652	        setBoxRect(null);
653	        return;
654	      }
655	      boxStartRef.current = null;
656	      boxRectRef.current = null;
657	
658	      const selLeft = Math.min(br.x1, br.x2);
659	      const selTop = Math.min(br.y1, br.y2);
660	      const selRight = Math.max(br.x1, br.x2);
661	      const selBottom = Math.max(br.y1, br.y2);
662	
663	      if (selRight - selLeft < 6 && selBottom - selTop < 6) {
664	        setBoxRect(null);
665	        return;
666	      }
667	
668	      const containerRect = containerRef.current?.getBoundingClientRect();
669	      if (!containerRect) {
670	        setBoxRect(null);
671	        return;
672	      }
673	
674	      const hits: string[] = [];
675	      const paneEls =
676	        containerRef.current?.querySelectorAll<HTMLElement>("[data-pane-id]");
677	      paneEls?.forEach((el) => {
678	        const paneId = el.dataset.paneId;
679	        if (!paneId) return;
680	        const r = el.getBoundingClientRect();
681	        const paneLeft = r.left - containerRect.left;
682	        const paneTop = r.top - containerRect.top;
683	        const paneRight = paneLeft + r.width;
684	        const paneBottom = paneTop + r.height;
685	        if (
686	          paneLeft < selRight &&
687	          paneRight > selLeft &&
688	          paneTop < selBottom &&
689	          paneBottom > selTop
690	        ) {
691	          hits.push(paneId);
692	        }
693	      });
694	
695	      if (hits.length > 0) {
696	        if (onSelectManyPanes) {
697	          onSelectManyPanes(hits);
698	        } else {
699	          hits.forEach((id, i) => onSelectPane(id, i > 0));
700	        }
701	      }
702	
703	      setBoxRect(null);
704	    },
705	    [onSelectPane, onSelectManyPanes],
706	  );
707	
708	  const handleGridContextMenu = useCallback(
709	    (e: React.MouseEvent<HTMLDivElement>) => {
710	      // Only fire for clicks on the grid background, not on pane elements
711	      const target = e.target as HTMLElement;
712	      const isPaneArea = !!target.closest("[data-pane-id]");
713	      if (!isPaneArea && onWorkspaceContextMenu) {
714	        e.preventDefault();
715	        onWorkspaceContextMenu(e.clientX, e.clientY);
716	      }
717	    },
718	    [onWorkspaceContextMenu],
719	  );
720	
721	  const handleGridDragOver = useCallback(
722	    (e: React.DragEvent<HTMLDivElement>) => {
723	      if (!onGridBackgroundDrop) return;
724	      if (!e.dataTransfer.types.includes(CONSOLE_DRAG_KEY)) return;
725	      // Only accept drops on empty background (not on a pane)
726	      const target = e.target as HTMLElement;
727	      if (target.closest("[data-pane-id]")) return;
728	      e.preventDefault();
729	      e.dataTransfer.dropEffect = "copy";
730	    },
731	    [onGridBackgroundDrop],
732	  );
733	
734	  const handleGridDrop = useCallback(
735	    (e: React.DragEvent<HTMLDivElement>) => {
736	      if (!onGridBackgroundDrop) return;
737	      const target = e.target as HTMLElement;
738	      if (target.closest("[data-pane-id]")) return;
739	      const raw = e.dataTransfer.getData(CONSOLE_DRAG_KEY);
740	      if (!raw) return;
741	      try {
742	        const item: ConsoleDragItem = JSON.parse(raw);
743	        e.preventDefault();
744	        onGridBackgroundDrop(item);
745	      } catch {
746	        // malformed payload — ignore
747	      }
748	    },
749	    [onGridBackgroundDrop],
750	  );
751	
752	  return (
753	    <div
754	      ref={containerRef}
755	      style={{
756	        flex: 1,
757	        overflow: "hidden",
758	        position: "relative",
759	        height: "100%",
760	        userSelect: "none",
761	      }}
762	      onPointerDown={handleGridPointerDown}
763	      onPointerMove={handleGridPointerMove}
764	      onPointerUp={handleGridPointerUp}
765	      onPointerCancel={handleGridPointerCancel}
766	      onContextMenu={handleGridContextMenu}
767	      onDragStart={(e) => e.preventDefault()}
768	      onDragOver={handleGridDragOver}
769	      onDrop={handleGridDrop}
770	    >
771	      <GridLayout
772	        layout={layoutWithConstraints}
773	        width={containerWidth}
774	        gridConfig={{
775	          cols: GRID_COLS,
776	          rowHeight,
777	          margin: [0, 0],
778	          containerPadding: [0, 0],
779	          maxRows: Infinity,
780	        }}
781	        dragConfig={{
782	          enabled: !locked,
783	          handle: ".io-pane-drag-handle",
784	          bounded: false,
785	          threshold: 3,
786	        }}
787	        resizeConfig={{
788	          enabled: !locked,
789	          handles: ["se", "sw", "ne", "nw", "e", "w", "n", "s"],
790	        }}
791	        compactor={gridCompactor}
792	        autoSize={false}
793	        style={{ height: "100%" }}
794	        onLayoutChange={handleLayoutChange}
795	        onDragStart={handleDragStart}
796	        onDrag={handleDrag}
797	        onDragStop={handleDragStop}
798	        onResizeStart={handleResizeStart}
799	        onResize={handleResize}
800	        onResizeStop={handleResizeStop}
801	        className="io-workspace-grid"
802	      >
803	        {layoutWithConstraints.map((item) => {
804	          const pane = paneById.get(item.i);
805	          if (!pane) return null;
806	          // Hide ALL grid items while any pane is fullscreen — the fullscreen pane
807	          // is rendered via a portal outside the RGL transform ancestor (spec §5.11).
808	          const isHiddenForFullscreen = fullscreenPaneId !== null;
809	          const retryCount = paneRetryCounters.get(pane.id) ?? 0;
810	          return (
811	            <div
812	              key={pane.id}
813	              data-pane-id={pane.id}
814	              style={{
815	                overflow: "hidden",
816	                display: isHiddenForFullscreen ? "none" : undefined,
817	              }}
818	            >
819	              <ErrorBoundary
820	                key={`${pane.id}-${retryCount}`}
821	                module={`Pane ${pane.id.slice(0, 8)}`}
822	                fallback={
823	                  <div
824	                    style={{
825	                      height: "100%",
826	                      display: "flex",
827	                      flexDirection: "column",
828	                      alignItems: "center",
829	                      justifyContent: "center",
830	                      gap: "8px",
831	                      color: "var(--io-text-muted)",
