834	                      padding: "16px",
835	                    }}
836	                  >
837	                    <div>Pane failed to render.</div>
838	                    <button
839	                      onClick={() => retryPane(pane.id)}
840	                      style={{
841	                        padding: "4px 12px",
842	                        borderRadius: "var(--io-radius)",
843	                        border: "1px solid var(--io-border)",
844	                        background: "var(--io-surface)",
845	                        color: "var(--io-text-primary)",
846	                        cursor: "pointer",
847	                        fontSize: 12,
848	                      }}
849	                    >
850	                      Retry
851	                    </button>
852	                  </div>
853	                }
854	              >
855	                <PaneWrapper
856	                  config={pane}
857	                  locked={locked}
858	                  isSelected={selectedPaneIds?.has(pane.id) ?? false}
859	                  isFullscreen={false}
860	                  onToggleFullscreen={() => toggleFullscreen(pane.id)}
861	                  onConfigure={onConfigurePane}
862	                  onRemove={onRemovePane}
863	                  onSelect={onSelectPane}
864	                  onPaletteDrop={onPaletteDrop}
865	                  preserveAspectRatio={preserveAspectRatio}
866	                  hideTitles={hideTitles}
867	                  swapModeSourceId={swapModeSourceId}
868	                  onSwapWith={onSwapWith}
869	                  onSwapComplete={onSwapComplete}
870	                  onReplace={onReplace}
871	                  onPinToggle={onPinToggle}
872	                  workspaceId={workspace.id}
873	                  onWorkspaceContextMenu={onWorkspaceContextMenu}
874	                />
875	              </ErrorBoundary>
876	            </div>
877	          );
878	        })}
879	      </GridLayout>
880	
881	      {/* Fullscreen portal (spec §5.11) ─────────────────────────────────────
882	          Rendered OUTSIDE GridLayout so `position:absolute` is relative to the
883	          workspace container (position:relative) rather than the RGL item's
884	          `transform:translate()` ancestor, which would trap a `position:fixed`
885	          child inside its bounding box.                                        */}
886	      {fullscreenPaneId !== null &&
887	        containerRef.current &&
888	        (() => {
889	          const fsPane = paneById.get(fullscreenPaneId);
890	          if (!fsPane) return null;
891	          const retryCount = paneRetryCounters.get(fsPane.id) ?? 0;
892	          return createPortal(
893	            <div
894	              className={`io-pane-fullscreen-portal${fsExiting ? " io-pane-fullscreen-exiting" : ""}`}
895	              style={{ position: "absolute", inset: 0, zIndex: 500 }}
896	            >
897	              <ErrorBoundary
898	                key={`${fsPane.id}-${retryCount}-fs`}
899	                module={`Pane ${fsPane.id.slice(0, 8)}`}
900	                fallback={
901	                  <div
902	                    style={{
903	                      height: "100%",
904	                      display: "flex",
905	                      flexDirection: "column",
906	                      alignItems: "center",
907	                      justifyContent: "center",
908	                      gap: "8px",
909	                      color: "var(--io-text-muted)",
910	                      fontSize: 13,
911	                      background: "var(--io-surface-secondary)",
912	                      padding: "16px",
913	                    }}
914	                  >
915	                    <div>Pane failed to render.</div>
916	                    <button
917	                      onClick={() => retryPane(fsPane.id)}
918	                      style={{
919	                        padding: "4px 12px",
920	                        borderRadius: "var(--io-radius)",
921	                        border: "1px solid var(--io-border)",
922	                        background: "var(--io-surface)",
923	                        color: "var(--io-text-primary)",
924	                        cursor: "pointer",
925	                        fontSize: 12,
926	                      }}
927	                    >
928	                      Retry
929	                    </button>
930	                  </div>
931	                }
932	              >
933	                <PaneWrapper
934	                  config={fsPane}
935	                  locked={locked}
936	                  isSelected={selectedPaneIds?.has(fsPane.id) ?? false}
937	                  isFullscreen={true}
938	                  onToggleFullscreen={exitFullscreen}
939	                  onConfigure={onConfigurePane}
940	                  onRemove={onRemovePane}
941	                  onSelect={onSelectPane}
942	                  onPaletteDrop={onPaletteDrop}
943	                  preserveAspectRatio={preserveAspectRatio}
944	                  hideTitles={hideTitles}
945	                  swapModeSourceId={swapModeSourceId}
946	                  onSwapWith={onSwapWith}
947	                  onSwapComplete={onSwapComplete}
948	                  onReplace={onReplace}
949	                  workspaceId={workspace.id}
950	                />
951	              </ErrorBoundary>
952	            </div>,
953	            containerRef.current,
954	          );
955	        })()}
956	
957	      {/* Drag/resize preview — ghost outlines for displaced panes ────────────
958	          Rendered only when a gesture is active. Each ghost shows where a
959	          non-active pane will end up after collision resolution. The active
960	          pane itself is excluded (RGL's own placeholder covers it).          */}
961	      {previewLayout &&
962	        !locked &&
963	        (() => {
964	          const activeId = gestureIdRef.current;
965	          const colWidth = containerWidth / GRID_COLS;
966	
967	          // Displaced-pane ghosts: panes (other than the active one) whose
968	          // resolved position differs from their current stored position.
969	          const ghosts = previewLayout.filter((preview) => {
970	            if (preview.i === activeId) return false;
971	            const current = gridItems.find((g) => g.i === preview.i);
972	            if (!current) return false;
973	            return (
974	              preview.x !== current.x ||
975	              preview.y !== current.y ||
976	              preview.w !== current.w ||
977	              preview.h !== current.h
978	            );
979	          });
980	
981	          if (ghosts.length === 0) return null;
982	
983	          return (
984	            <div
985	              style={{
986	                position: "absolute",
987	                inset: 0,
988	                pointerEvents: "none",
989	                zIndex: 40,
990	              }}
991	            >
