993	                <div
994	                  key={preview.i}
995	                  style={{
996	                    position: "absolute",
997	                    left: preview.x * colWidth,
998	                    top: preview.y * rowHeight,
999	                    width: preview.w * colWidth,
1000	                    height: preview.h * rowHeight,
1001	                    border: "2px dashed var(--io-accent)",
1002	                    background: "var(--io-accent-subtle)",
1003	                    boxSizing: "border-box",
1004	                    borderRadius: "var(--io-radius)",
1005	                    opacity: 0.75,
1006	                    transition:
1007	                      "left 60ms ease, top 60ms ease, width 60ms ease, height 60ms ease",
1008	                  }}
1009	                />
1010	              ))}
