1019	            position: "absolute",
1020	            left: Math.min(boxRect.x1, boxRect.x2),
1021	            top: Math.min(boxRect.y1, boxRect.y2),
1022	            width: Math.abs(boxRect.x2 - boxRect.x1),
1023	            height: Math.abs(boxRect.y2 - boxRect.y1),
1024	            border: "1px solid var(--io-accent)",
