import React, {
  useRef,
  useEffect,
  useState,
  useCallback,
  useMemo,
} from "react";
import { createPortal } from "react-dom";
import { GridLayout, noCompactor, type LayoutItem } from "react-grid-layout";
import "react-grid-layout/css/styles.css";
import "react-resizable/css/styles.css";
import "./WorkspaceGrid.css";
import PaneWrapper from "./PaneWrapper";
import { ErrorBoundary } from "../../shared/components/ErrorBoundary";
import { CONSOLE_DRAG_KEY, type ConsoleDragItem } from "./ConsolePalette";
import type { WorkspaceLayout, PaneConfig, GridItem } from "./types";
import {
  GRID_COLS,
  GRID_ROWS,
  MIN_W,
  MIN_H,
  presetToGridItems,
  scanLineCompact,
} from "./layout-utils";

export { presetToGridItems };

// ---------------------------------------------------------------------------
// gridCompactor — noCompactor with allowOverlap:true
// ---------------------------------------------------------------------------
//
// RGL's noCompactor (type:null, allowOverlap:false) has a special branch in
// moveElementAwayFromCollision that fires when compactType===null and there is
// a north collision during a user action. It swaps the y positions of the two
// items, causing the pane to teleport to y=0 mid-drag and the neighbour to get
// pushed far down. This only manifests for north/NW/NE resize because those are
// the only handles that move the item's y position during the drag.
//
// Setting allowOverlap:true makes moveElement return early (cloneLayout) when
// collisions are detected, so items can overlap during the interaction. Our
// handleResizeStop / handleDragStop already call resolveCollisions to clean up
// at the end of every gesture — allowOverlap here just keeps the mid-drag
// frames clean.

const gridCompactor = { ...noCompactor, allowOverlap: true };

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

export interface WorkspaceGridProps {
  workspace: WorkspaceLayout;
  /** When true, all drag/resize/remove/pin interactions are disabled. */
  locked?: boolean;
  /** Set of pane IDs that are pinned (protected from displacement). */
  pinnedIds?: Set<string>;
  selectedPaneIds?: Set<string>;
  preserveAspectRatio?: boolean;
  /** When true, all pane title bars are suppressed (workspace-level TT toggle). */
  hideTitles?: boolean;
  onConfigurePane: (paneId: string) => void;
  onRemovePane: (paneId: string) => void;
  onSelectPane?: (paneId: string, addToSelection: boolean) => void;
  /** Atomically replace the selection with a set of pane IDs (used by marquee). */
  onSelectManyPanes?: (paneIds: string[]) => void;
  onPaletteDrop?: (paneId: string, item: ConsoleDragItem) => void;
  onGridLayoutChange?: (items: GridItem[]) => void;
  /** Called when user right-clicks the workspace background (not on a pane) */
  onWorkspaceContextMenu?: (x: number, y: number) => void;
  /** Pane ID that initiated "Swap With..." mode */
  swapModeSourceId?: string | null;
  /** Called when user clicks "Swap With..." on a pane */
  onSwapWith?: (paneId: string) => void;
  /** Called when user clicks a swap target pane */
  onSwapComplete?: (targetId: string) => void;
  /** Called when user selects a new graphic in the Replace dialog */
  onReplace?: (paneId: string, graphicId: string, graphicName: string) => void;
  /** Called when F11 is pressed with no pane selected — triggers workspace browser fullscreen */
  onBrowserFullscreen?: () => void;
  /** Called when pin state changes on a pane */
  onPinToggle?: (paneId: string, pinned: boolean) => void;
  /** Called when a palette item is dropped onto empty grid space (not on any pane) */
  onGridBackgroundDrop?: (item: ConsoleDragItem) => void;
}

// ---------------------------------------------------------------------------
// WorkspaceGrid — react-grid-layout (12-col drag-resize, doc 07)
// ---------------------------------------------------------------------------

export default function WorkspaceGrid({
  workspace,
  locked = false,
  pinnedIds = new Set<string>(),
  selectedPaneIds,
  preserveAspectRatio = true,
  hideTitles = false,
  onConfigurePane,
  onWorkspaceContextMenu,
  onRemovePane,
  onSelectPane,
  onSelectManyPanes,
  onPaletteDrop,
  onGridLayoutChange,
  swapModeSourceId,
  onSwapWith,
  onSwapComplete,
  onReplace,
  onBrowserFullscreen,
  onPinToggle,
  onGridBackgroundDrop,
}: WorkspaceGridProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [containerWidth, setContainerWidth] = useState(800);
  const [containerHeight, setContainerHeight] = useState(600);

  // ── Per-pane error boundary retry counters ───────────────────────────────
  const [paneRetryCounters, setPaneRetryCounters] = useState<
    Map<string, number>
  >(new Map());

  const retryPane = useCallback((paneId: string) => {
    setPaneRetryCounters((prev) => {
      const next = new Map(prev);
      next.set(paneId, (prev.get(paneId) ?? 0) + 1);
      return next;
    });
  }, []);

  // ── Fullscreen state (spec §5.11) ────────────────────────────────────────
  // Active fullscreen pane ID, or null when not in fullscreen.
  const [fullscreenPaneId, setFullscreenPaneId] = useState<string | null>(null);
  // When true, the exit animation is playing (portal is still mounted, fading out).
  const [fsExiting, setFsExiting] = useState(false);
  const fsExitTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // exitFullscreen — plays the 200ms exit animation then clears state.
  const exitFullscreen = useCallback(() => {
    setFsExiting(true);
    if (fsExitTimerRef.current) clearTimeout(fsExitTimerRef.current);
    fsExitTimerRef.current = setTimeout(() => {
      setFullscreenPaneId(null);
      setFsExiting(false);
    }, 210); // 210ms > 200ms animation so the frame completes before unmount
  }, []);

  const toggleFullscreen = useCallback(
    (paneId: string) => {
      if (
        fullscreenPaneId === paneId ||
        (fullscreenPaneId !== null && fsExiting)
      ) {
        exitFullscreen();
      } else {
        // Cancel any in-progress exit and enter the new pane immediately.
        if (fsExitTimerRef.current) {
          clearTimeout(fsExitTimerRef.current);
          fsExitTimerRef.current = null;
        }
        setFsExiting(false);
        setFullscreenPaneId(paneId);
      }
    },
    [fullscreenPaneId, fsExiting, exitFullscreen],
  );

  // Clean up exit timer on unmount.
  useEffect(
    () => () => {
      if (fsExitTimerRef.current) clearTimeout(fsExitTimerRef.current);
    },
    [],
  );

  // F11 keyboard shortcut: toggle fullscreen on single selected pane (spec §5.11)
  // Precedence: pane fullscreen > workspace browser fullscreen (decision CX-CONSOLE-WORKSPACE-FULLSCREEN)
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (e.key === "F11") {
        e.preventDefault();
        if (fullscreenPaneId !== null) {
          // A pane is already in pane-fullscreen — exit it
          exitFullscreen();
          return;
        }
        if (selectedPaneIds && selectedPaneIds.size === 1) {
          // A pane is selected — enter pane fullscreen
          const [paneId] = selectedPaneIds;
          setFullscreenPaneId(paneId);
          return;
        }
        // No pane selected and no pane in fullscreen — fall through to workspace browser fullscreen
        onBrowserFullscreen?.();
      }
      if (e.key === "Escape" && fullscreenPaneId !== null) {
        exitFullscreen();
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [fullscreenPaneId, selectedPaneIds, exitFullscreen, onBrowserFullscreen]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const ro = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerWidth(entry.contentRect.width);
        setContainerHeight(entry.contentRect.height);
      }
    });
    ro.observe(el);
    setContainerWidth(el.clientWidth);
    setContainerHeight(el.clientHeight);
    return () => ro.disconnect();
  }, []);

  const safePanes: PaneConfig[] = workspace.panes ?? [];

  const gridItems: GridItem[] = workspace.gridItems?.length
    ? workspace.gridItems
    : presetToGridItems(workspace.layout, safePanes);

  // Always-current ref: callbacks (handleResizeStop, handleDragStop) capture
  // gridItems at closure creation time. If a second gesture starts before React
  // re-renders from the first gesture's onGridLayoutChange, those callbacks see
  // stale positions. Assigning the ref during render (not in useEffect) ensures
  // it's synchronously up-to-date on every render cycle.
  const gridItemsRef = useRef(gridItems);
  gridItemsRef.current = gridItems;

  const paneById = useMemo(
    () => new Map<string, PaneConfig>(safePanes.map((p) => [p.id, p])),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [workspace.panes],
  );

  // rowHeight: container divided by 288 rows — gives ~2px per row at 600px height
  const rowHeight = Math.max(1, containerHeight / GRID_ROWS);

  // Track whether a drag or resize is in progress so handleLayoutChange skips
  // the store update during intermediate frames. RGL fires onLayoutChange on
  // every mouse-move during drag/resize; we only want the final settled layout
  // (from onDragStop / onResizeStop) written to the store.
  const isDraggingRef = useRef(false);
  const isResizingRef = useRef(false);

  // Shift+corner aspect-ratio lock: record starting grid dimensions when resize begins.
  // On stop, if shift is held and both w and h changed, we snap h to maintain the
  // starting w/h grid-unit ratio. (Separate from the AR button, which locks to the
  // underlying graphic's pixel aspect ratio.)
  const shiftKeyRef = useRef(false);
  const resizeStartRef = useRef<{
    i: string;
    x: number;
    y: number;
    w: number;
    h: number;
  } | null>(null);

  // ── Drag/resize preview (ghost outlines for displaced panes) ─────────────
  // gestureIdRef: ID of the pane currently being dragged/resized (excluded
  //   from ghost rendering — it already has RGL's own placeholder).
  // previewLayout: resolved layout computed on every onDrag/onResize frame.
  // rawGestureLayout: unclamped layout as reported by RGL (before resolveCollisions).
  //   Used to detect when moved was capped below the user's drag position so
  //   we can render a ghost showing the actual committed size.
  const gestureIdRef = useRef<string | null>(null);
  const [previewLayout, setPreviewLayout] = useState<GridItem[] | null>(null);
  const preGestureLayoutRef = useRef<GridItem[] | null>(null);

  useEffect(() => {
    const onDown = (e: KeyboardEvent) => {
      if (e.key === "Shift") shiftKeyRef.current = true;
    };
    const onUp = (e: KeyboardEvent) => {
      if (e.key === "Shift") shiftKeyRef.current = false;
    };
    window.addEventListener("keydown", onDown);
    window.addEventListener("keyup", onUp);
    return () => {
      window.removeEventListener("keydown", onDown);
      window.removeEventListener("keyup", onUp);
    };
  }, []);

  const handleDragStart = useCallback(() => {
    isDraggingRef.current = true;
    preGestureLayoutRef.current = gridItemsRef.current.map((it) => ({ ...it }));
  }, []);

  const handleDrag = useCallback(
    (
      _layout: readonly LayoutItem[],
      _old: LayoutItem | null,
      newItem: LayoutItem | null,
    ) => {
      if (!newItem) return;
      gestureIdRef.current = newItem.i;
      const withNewPos = gridItemsRef.current.map(
        (item): GridItem =>
          item.i === newItem.i
            ? {
                i: item.i,
                x: newItem.x,
                y: newItem.y,
                w: newItem.w,
                h: newItem.h,
              }
            : item,
      );
      setPreviewLayout(
        scanLineCompact(
          withNewPos,
          newItem.i,
          pinnedIds,
          preGestureLayoutRef.current,
          GRID_COLS,
          GRID_ROWS,
        ),
      );
    },
    [pinnedIds],
  );

  const handleResize = useCallback(
    (
      _layout: readonly LayoutItem[],
      _old: LayoutItem | null,
      newItem: LayoutItem | null,
    ) => {
      if (!newItem) return;
      gestureIdRef.current = newItem.i;
      const withNewSize = gridItemsRef.current.map(
        (item): GridItem =>
          item.i === newItem.i
            ? {
                i: item.i,
                x: newItem.x,
                y: newItem.y,
                w: newItem.w,
                h: newItem.h,
              }
            : item,
      );
      setPreviewLayout(
        scanLineCompact(
          withNewSize,
          newItem.i,
          pinnedIds,
          preGestureLayoutRef.current,
          GRID_COLS,
          GRID_ROWS,
        ),
      );
    },
    [pinnedIds],
  );

  const handleResizeStart = useCallback(
    (
      _layout: readonly LayoutItem[],
      _oldItem: LayoutItem | null,
      newItem: LayoutItem | null,
    ) => {
      isResizingRef.current = true;
      preGestureLayoutRef.current = gridItemsRef.current.map((it) => ({
        ...it,
      }));
      if (newItem) {
        resizeStartRef.current = {
          i: newItem.i,
          x: newItem.x,
          y: newItem.y,
          w: newItem.w,
          h: newItem.h,
        };
      }
    },
    [],
  );

  const handleLayoutChange = useCallback(
    (layout: readonly LayoutItem[]) => {
      if (locked || !onGridLayoutChange) return;
      // Skip intermediate frames during active drag/resize — the stop handlers
      // apply the final resolved layout once the gesture completes.
      if (isDraggingRef.current || isResizingRef.current) return;
      onGridLayoutChange(
        layout.map((item) => ({
          i: item.i,
          x: item.x,
          y: item.y,
          w: item.w,
          h: item.h,
        })),
      );
    },
    [locked, onGridLayoutChange],
  );

  // ── Resize stop — scan-line compaction ───────────────────────────────────

  const handleResizeStop = useCallback(
    (
      _layout: readonly LayoutItem[],
      _oldItem: LayoutItem | null,
      newItem: LayoutItem | null,
    ) => {
      // Keep isResizingRef true until the next animation frame — RGL calls
      // onLayoutChange(finalLayout) synchronously after this handler returns,
      // and we need handleLayoutChange to ignore that unresolved layout.
      requestAnimationFrame(() => {
        isResizingRef.current = false;
      });
      setPreviewLayout(null);
      gestureIdRef.current = null;
      const preGesture = preGestureLayoutRef.current;
      preGestureLayoutRef.current = null;
      const startDims = resizeStartRef.current;
      resizeStartRef.current = null;

      if (locked || !onGridLayoutChange || !newItem) return;

      let finalW = newItem.w;
      let finalH = newItem.h;

      // Shift+corner: lock to starting grid-unit aspect ratio.
      // Only fires when both w and h changed (corner handle), not side handles.
      if (
        shiftKeyRef.current &&
        startDims?.i === newItem.i &&
        newItem.w !== startDims.w &&
        newItem.h !== startDims.h
      ) {
        const ar = startDims.w / startDims.h; // grid-unit ratio
        const wScale = newItem.w / startDims.w;
        const hScale = newItem.h / startDims.h;
        // Honour whichever axis changed proportionally more
        if (wScale >= hScale) {
          finalH = Math.max(MIN_H, Math.round(newItem.w / ar));
        } else {
          finalW = Math.max(MIN_W, Math.round(newItem.h * ar));
        }
      }

      const withNewSize = gridItemsRef.current.map(
        (item): GridItem =>
          item.i === newItem.i
            ? { i: item.i, x: newItem.x, y: newItem.y, w: finalW, h: finalH }
            : item,
      );
      onGridLayoutChange(
        scanLineCompact(
          withNewSize,
          newItem.i,
          pinnedIds,
          preGesture,
          GRID_COLS,
          GRID_ROWS,
        ),
      );
    },
    [locked, pinnedIds, onGridLayoutChange],
  );

  // ── Drag stop — scan-line compaction ─────────────────────────────────────

  const handleDragStop = useCallback(
    (
      _layout: readonly LayoutItem[],
      _oldItem: LayoutItem | null,
      newItem: LayoutItem | null,
    ) => {
      // Keep isDraggingRef true until the next animation frame — RGL calls
      // onLayoutChange(finalLayout) synchronously after this handler returns,
      // and we need handleLayoutChange to ignore that unresolved layout.
      requestAnimationFrame(() => {
        isDraggingRef.current = false;
      });
      setPreviewLayout(null);
      gestureIdRef.current = null;
      const preGesture = preGestureLayoutRef.current;
      preGestureLayoutRef.current = null;

      if (locked || !onGridLayoutChange) return;

      if (!newItem) {
        onGridLayoutChange(gridItems);
        return;
      }

      const withNewPos = gridItemsRef.current.map(
        (item): GridItem =>
          item.i === newItem.i
            ? {
                i: item.i,
                x: newItem.x,
                y: newItem.y,
                w: newItem.w,
                h: newItem.h,
              }
            : item,
      );
      onGridLayoutChange(
        scanLineCompact(
          withNewPos,
          newItem.i,
          pinnedIds,
          preGesture,
          GRID_COLS,
          GRID_ROWS,
        ),
      );
    },
    [locked, pinnedIds, onGridLayoutChange, gridItems],
  );

  // Augment grid items with min size constraints
  const layoutWithConstraints: LayoutItem[] = gridItems.map((item) => ({
    ...item,
    minW: MIN_W,
    minH: MIN_H,
  }));

  // ── Box selection ──────────────────────────────────────────────────────────

  // boxRect state drives the visual marquee overlay only.
  // All handler logic reads boxRectRef so it never has a stale React closure.
  const [boxRect, setBoxRect] = useState<{
    x1: number;
    y1: number;
    x2: number;
    y2: number;
  } | null>(null);
  const boxRectRef = useRef<{
    x1: number;
    y1: number;
    x2: number;
    y2: number;
  } | null>(null);
  const boxStartRef = useRef<{ x: number; y: number } | null>(null);
  // Tracks physical button state: true between pointerdown and pointerup.
  // Rejects a second pointerdown while the button is already held — mirrors
  // DesignerCanvas.tsx:3088 (inter.type !== "none" guard).
  const isPointerDownRef = useRef(false);
  // Tracks whether pointer capture has been set for the current drag.
  // Capture is deferred until actual movement so that single clicks do NOT
  // redirect the browser's synthesised click event to the container (which has
  // no onClick handler), which was preventing PaneWrapper.handlePaneClick from
  // firing on simple clicks.
  const hasCaptureRef = useRef(false);
  // True when the current pointer-down originated inside pane content (not a
  // drag handle). Drags from pane content are handled by the pane itself (e.g.
  // GraphicPane node marquee); WorkspaceGrid must not capture or show its own
  // pane-selection marquee in that case.
  const startedInPaneContentRef = useRef(false);

  const handleGridPointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (locked || !onSelectPane) return;
      if (!e.isPrimary || e.button !== 0) return;
      // Ignore any pointerdown that arrives while the button is already held.
      if (isPointerDownRef.current) return;
      if (boxStartRef.current) return;
      const target = e.target as HTMLElement;
      if (target.closest(".io-pane-drag-handle")) return;
      if (!containerRef.current?.contains(target)) return;
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      // Do NOT setPointerCapture here — defer it to first real pointermove so
      // that single-click still fires on the pane element, not the container.
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      isPointerDownRef.current = true;
      hasCaptureRef.current = false;
      startedInPaneContentRef.current = !!target.closest("[data-pane-id]");
      boxStartRef.current = { x, y };
      const r = { x1: x, y1: y, x2: x, y2: y };
      boxRectRef.current = r;
    },
    [locked, onSelectPane],
  );

  const handleGridPointerMove = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (!boxStartRef.current || !e.isPrimary) return;
      // Pane-content drags belong to the pane — skip pane-selection marquee.
      if (startedInPaneContentRef.current) return;
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      // Acquire pointer capture on first real move (>= 3px) so the marquee
      // continues to receive events if the cursor leaves the container, while
      // still allowing click events to land on pane elements for single-clicks.
      if (!hasCaptureRef.current) {
        const dx = x - boxStartRef.current.x;
        const dy = y - boxStartRef.current.y;
        if (Math.abs(dx) >= 3 || Math.abs(dy) >= 3) {
          e.currentTarget.setPointerCapture(e.pointerId);
          hasCaptureRef.current = true;
          setBoxRect(boxRectRef.current); // now show the marquee
        } else {
          return; // not enough movement yet
        }
      }
      const r = {
        x1: boxStartRef.current.x,
        y1: boxStartRef.current.y,
        x2: x,
        y2: y,
      };
      boxRectRef.current = r;
      setBoxRect(r);
    },
    [],
  );

  const handleGridPointerCancel = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (!e.isPrimary) return;
      isPointerDownRef.current = false;
      hasCaptureRef.current = false;
      startedInPaneContentRef.current = false;
      boxStartRef.current = null;
      boxRectRef.current = null;
      setBoxRect(null);
    },
    [],
  );

  const handleGridPointerUp = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (!e.isPrimary) return;
      // Always clear button-state at the top, before any early returns.
      isPointerDownRef.current = false;
      hasCaptureRef.current = false;
      const startedInContent = startedInPaneContentRef.current;
      startedInPaneContentRef.current = false;
      if (startedInContent) {
        boxStartRef.current = null;
        boxRectRef.current = null;
        setBoxRect(null);
        return;
      }
      // Read from ref — never from the React state closure which may be stale
      // if React deferred the commit of the last setBoxRect call.
      const br = boxRectRef.current;
      if (!boxStartRef.current || !br || !onSelectPane) {
        boxStartRef.current = null;
        boxRectRef.current = null;
        setBoxRect(null);
        return;
      }
      boxStartRef.current = null;
      boxRectRef.current = null;

      const selLeft = Math.min(br.x1, br.x2);
      const selTop = Math.min(br.y1, br.y2);
      const selRight = Math.max(br.x1, br.x2);
      const selBottom = Math.max(br.y1, br.y2);

      if (selRight - selLeft < 6 && selBottom - selTop < 6) {
        setBoxRect(null);
        return;
      }

      const containerRect = containerRef.current?.getBoundingClientRect();
      if (!containerRect) {
        setBoxRect(null);
        return;
      }

      const hits: string[] = [];
      const paneEls =
        containerRef.current?.querySelectorAll<HTMLElement>("[data-pane-id]");
      paneEls?.forEach((el) => {
        const paneId = el.dataset.paneId;
        if (!paneId) return;
        const r = el.getBoundingClientRect();
        const paneLeft = r.left - containerRect.left;
        const paneTop = r.top - containerRect.top;
        const paneRight = paneLeft + r.width;
        const paneBottom = paneTop + r.height;
        if (
          paneLeft < selRight &&
          paneRight > selLeft &&
          paneTop < selBottom &&
          paneBottom > selTop
        ) {
          hits.push(paneId);
        }
      });

      if (hits.length > 0) {
        if (onSelectManyPanes) {
          onSelectManyPanes(hits);
        } else {
          hits.forEach((id, i) => onSelectPane(id, i > 0));
        }
      }

      setBoxRect(null);
    },
    [onSelectPane, onSelectManyPanes],
  );

  const handleGridContextMenu = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      // Only fire for clicks on the grid background, not on pane elements
      const target = e.target as HTMLElement;
      const isPaneArea = !!target.closest("[data-pane-id]");
      if (!isPaneArea && onWorkspaceContextMenu) {
        e.preventDefault();
        onWorkspaceContextMenu(e.clientX, e.clientY);
      }
    },
    [onWorkspaceContextMenu],
  );

  const handleGridDragOver = useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      if (!onGridBackgroundDrop) return;
      if (!e.dataTransfer.types.includes(CONSOLE_DRAG_KEY)) return;
      // Only accept drops on empty background (not on a pane)
      const target = e.target as HTMLElement;
      if (target.closest("[data-pane-id]")) return;
      e.preventDefault();
      e.dataTransfer.dropEffect = "copy";
    },
    [onGridBackgroundDrop],
  );

  const handleGridDrop = useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      if (!onGridBackgroundDrop) return;
      const target = e.target as HTMLElement;
      if (target.closest("[data-pane-id]")) return;
      const raw = e.dataTransfer.getData(CONSOLE_DRAG_KEY);
      if (!raw) return;
      try {
        const item: ConsoleDragItem = JSON.parse(raw);
        e.preventDefault();
        onGridBackgroundDrop(item);
      } catch {
        // malformed payload — ignore
      }
    },
    [onGridBackgroundDrop],
  );

  return (
    <div
      ref={containerRef}
      style={{
        flex: 1,
        overflow: "hidden",
        position: "relative",
        height: "100%",
        userSelect: "none",
      }}
      onPointerDown={handleGridPointerDown}
      onPointerMove={handleGridPointerMove}
      onPointerUp={handleGridPointerUp}
      onPointerCancel={handleGridPointerCancel}
      onContextMenu={handleGridContextMenu}
      onDragStart={(e) => e.preventDefault()}
      onDragOver={handleGridDragOver}
      onDrop={handleGridDrop}
    >
      <GridLayout
        layout={layoutWithConstraints}
        width={containerWidth}
        gridConfig={{
          cols: GRID_COLS,
          rowHeight,
          margin: [0, 0],
          containerPadding: [0, 0],
          maxRows: Infinity,
        }}
        dragConfig={{
          enabled: !locked,
          handle: ".io-pane-drag-handle",
          bounded: false,
          threshold: 3,
        }}
        resizeConfig={{
          enabled: !locked,
          handles: ["se", "sw", "ne", "nw", "e", "w", "n", "s"],
        }}
        compactor={gridCompactor}
        autoSize={false}
        style={{ height: "100%" }}
        onLayoutChange={handleLayoutChange}
        onDragStart={handleDragStart}
        onDrag={handleDrag}
        onDragStop={handleDragStop}
        onResizeStart={handleResizeStart}
        onResize={handleResize}
        onResizeStop={handleResizeStop}
        className="io-workspace-grid"
      >
        {layoutWithConstraints.map((item) => {
          const pane = paneById.get(item.i);
          if (!pane) return null;
          // Hide ALL grid items while any pane is fullscreen — the fullscreen pane
          // is rendered via a portal outside the RGL transform ancestor (spec §5.11).
          const isHiddenForFullscreen = fullscreenPaneId !== null;
          const retryCount = paneRetryCounters.get(pane.id) ?? 0;
          return (
            <div
              key={pane.id}
              data-pane-id={pane.id}
              style={{
                overflow: "hidden",
                display: isHiddenForFullscreen ? "none" : undefined,
              }}
            >
              <ErrorBoundary
                key={`${pane.id}-${retryCount}`}
                module={`Pane ${pane.id.slice(0, 8)}`}
                fallback={
                  <div
                    style={{
                      height: "100%",
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "8px",
                      color: "var(--io-text-muted)",
                      fontSize: 13,
                      background: "var(--io-surface-secondary)",
                      padding: "16px",
                    }}
                  >
                    <div>Pane failed to render.</div>
                    <button
                      onClick={() => retryPane(pane.id)}
                      style={{
                        padding: "4px 12px",
                        borderRadius: "var(--io-radius)",
                        border: "1px solid var(--io-border)",
                        background: "var(--io-surface)",
                        color: "var(--io-text-primary)",
                        cursor: "pointer",
                        fontSize: 12,
                      }}
                    >
                      Retry
                    </button>
                  </div>
                }
              >
                <PaneWrapper
                  config={pane}
                  locked={locked}
                  isSelected={selectedPaneIds?.has(pane.id) ?? false}
                  isFullscreen={false}
                  onToggleFullscreen={() => toggleFullscreen(pane.id)}
                  onConfigure={onConfigurePane}
                  onRemove={onRemovePane}
                  onSelect={onSelectPane}
                  onPaletteDrop={onPaletteDrop}
                  preserveAspectRatio={preserveAspectRatio}
                  hideTitles={hideTitles}
                  swapModeSourceId={swapModeSourceId}
                  onSwapWith={onSwapWith}
                  onSwapComplete={onSwapComplete}
                  onReplace={onReplace}
                  onPinToggle={onPinToggle}
                  workspaceId={workspace.id}
                  onWorkspaceContextMenu={onWorkspaceContextMenu}
                />
              </ErrorBoundary>
            </div>
          );
        })}
      </GridLayout>

      {/* Fullscreen portal (spec §5.11) ─────────────────────────────────────
          Rendered OUTSIDE GridLayout so `position:absolute` is relative to the
          workspace container (position:relative) rather than the RGL item's
          `transform:translate()` ancestor, which would trap a `position:fixed`
          child inside its bounding box.                                        */}
      {fullscreenPaneId !== null &&
        containerRef.current &&
        (() => {
          const fsPane = paneById.get(fullscreenPaneId);
          if (!fsPane) return null;
          const retryCount = paneRetryCounters.get(fsPane.id) ?? 0;
          return createPortal(
            <div
              className={`io-pane-fullscreen-portal${fsExiting ? " io-pane-fullscreen-exiting" : ""}`}
              style={{ position: "absolute", inset: 0, zIndex: 500 }}
            >
              <ErrorBoundary
                key={`${fsPane.id}-${retryCount}-fs`}
                module={`Pane ${fsPane.id.slice(0, 8)}`}
                fallback={
                  <div
                    style={{
                      height: "100%",
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "8px",
                      color: "var(--io-text-muted)",
                      fontSize: 13,
                      background: "var(--io-surface-secondary)",
                      padding: "16px",
                    }}
                  >
                    <div>Pane failed to render.</div>
                    <button
                      onClick={() => retryPane(fsPane.id)}
                      style={{
                        padding: "4px 12px",
                        borderRadius: "var(--io-radius)",
                        border: "1px solid var(--io-border)",
                        background: "var(--io-surface)",
                        color: "var(--io-text-primary)",
                        cursor: "pointer",
                        fontSize: 12,
                      }}
                    >
                      Retry
                    </button>
                  </div>
                }
              >
                <PaneWrapper
                  config={fsPane}
                  locked={locked}
                  isSelected={selectedPaneIds?.has(fsPane.id) ?? false}
                  isFullscreen={true}
                  onToggleFullscreen={exitFullscreen}
                  onConfigure={onConfigurePane}
                  onRemove={onRemovePane}
                  onSelect={onSelectPane}
                  onPaletteDrop={onPaletteDrop}
                  preserveAspectRatio={preserveAspectRatio}
                  hideTitles={hideTitles}
                  swapModeSourceId={swapModeSourceId}
                  onSwapWith={onSwapWith}
                  onSwapComplete={onSwapComplete}
                  onReplace={onReplace}
                  workspaceId={workspace.id}
                />
              </ErrorBoundary>
            </div>,
            containerRef.current,
          );
        })()}

      {/* Drag/resize preview — ghost outlines for displaced panes ────────────
          Rendered only when a gesture is active. Each ghost shows where a
          non-active pane will end up after collision resolution. The active
          pane itself is excluded (RGL's own placeholder covers it).          */}
      {previewLayout &&
        !locked &&
        (() => {
          const activeId = gestureIdRef.current;
          const colWidth = containerWidth / GRID_COLS;

          // Displaced-pane ghosts: panes (other than the active one) whose
          // resolved position differs from their current stored position.
          const ghosts = previewLayout.filter((preview) => {
            if (preview.i === activeId) return false;
            const current = gridItems.find((g) => g.i === preview.i);
            if (!current) return false;
            return (
              preview.x !== current.x ||
              preview.y !== current.y ||
              preview.w !== current.w ||
              preview.h !== current.h
            );
          });

          if (ghosts.length === 0) return null;

          return (
            <div
              style={{
                position: "absolute",
                inset: 0,
                pointerEvents: "none",
                zIndex: 40,
              }}
            >
              {ghosts.map((preview) => (
                <div
                  key={preview.i}
                  style={{
                    position: "absolute",
                    left: preview.x * colWidth,
                    top: preview.y * rowHeight,
                    width: preview.w * colWidth,
                    height: preview.h * rowHeight,
                    border: "2px dashed var(--io-accent)",
                    background: "var(--io-accent-subtle)",
                    boxSizing: "border-box",
                    borderRadius: "var(--io-radius)",
                    opacity: 0.75,
                    transition:
                      "left 60ms ease, top 60ms ease, width 60ms ease, height 60ms ease",
                  }}
                />
              ))}
            </div>
          );
        })()}

      {/* Box selection rect */}
      {boxRect && !locked && (
        <div
          style={{
            position: "absolute",
            left: Math.min(boxRect.x1, boxRect.x2),
            top: Math.min(boxRect.y1, boxRect.y2),
            width: Math.abs(boxRect.x2 - boxRect.x1),
            height: Math.abs(boxRect.y2 - boxRect.y1),
            border: "1px solid var(--io-accent)",
            background: "var(--io-accent-subtle)",
            pointerEvents: "none",
            zIndex: 50,
          }}
        />
      )}
    </div>
  );
}

import { useState } from "react";
import * as Dialog from "@radix-ui/react-dialog";
import { useQuery } from "@tanstack/react-query";
import { pointsApi } from "../../api/points";
import type { PaneConfig, PaneType } from "./types";

interface PaneConfigModalProps {
  pane: PaneConfig;
  onSave: (updated: PaneConfig) => void;
  onClose: () => void;
}

const PANE_TYPES: { value: PaneType; label: string; description: string }[] = [
  { value: "trend", label: "Trend", description: "Real-time trend chart" },
  {
    value: "point_table",
    label: "Point Table",
    description: "Live point value table",
  },
  {
    value: "alarm_list",
    label: "Alarm List",
    description: "Active alarm list",
  },
  { value: "blank", label: "Blank", description: "Empty pane" },
];

// ---------------------------------------------------------------------------
// Point search section
// ---------------------------------------------------------------------------

function PointSearch({
  selected,
  onChange,
  maxSelect,
}: {
  selected: string[];
  onChange: (ids: string[]) => void;
  maxSelect?: number;
}) {
  const [query, setQuery] = useState("");

  const { data, isFetching } = useQuery({
    queryKey: ["points-search", query],
    queryFn: async () => {
      const result = await pointsApi.list({
        search: query || undefined,
        limit: 50,
      });
      if (!result.success) throw new Error(result.error.message);
      return result.data.data;
    },
    staleTime: 15_000,
  });

  const toggle = (id: string) => {
    if (selected.includes(id)) {
      onChange(selected.filter((x) => x !== id));
    } else {
      if (maxSelect && selected.length >= maxSelect) return;
      onChange([...selected, id]);
    }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      <input
        type="text"
        placeholder="Search points by name or tag…"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        style={{
          background: "var(--io-surface-secondary)",
          border: "1px solid var(--io-border)",
          borderRadius: 6,
          padding: "7px 10px",
          fontSize: 13,
          color: "var(--io-text-primary)",
          outline: "none",
        }}
      />

      {maxSelect && (
        <div style={{ fontSize: 11, color: "var(--io-text-muted)" }}>
          {selected.length} / {maxSelect} selected
        </div>
      )}

      {isFetching && (
        <div style={{ fontSize: 12, color: "var(--io-text-muted)" }}>
          Searching…
        </div>
      )}

      <div
        style={{
          display: "flex",
          flexDirection: "column",
          gap: 4,
          maxHeight: 200,
          overflowY: "auto",
        }}
      >
        {data?.map((pt) => {
          const isSelected = selected.includes(pt.id);
          const isDisabled =
            !isSelected && maxSelect != null && selected.length >= maxSelect;
          return (
            <label
              key={pt.id}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 10,
                padding: "6px 10px",
                background: isSelected
                  ? "var(--io-accent-subtle, rgba(74,158,255,0.1))"
                  : "var(--io-surface-secondary)",
                border: `1px solid ${isSelected ? "var(--io-accent)" : "var(--io-border)"}`,
                borderRadius: 6,
                cursor: isDisabled ? "not-allowed" : "pointer",
                opacity: isDisabled ? 0.5 : 1,
                fontSize: 13,
              }}
            >
              <input
                type="checkbox"
                checked={isSelected}
                disabled={isDisabled}
                onChange={() => toggle(pt.id)}
                style={{ accentColor: "var(--io-accent)" }}
              />
              <span style={{ flex: 1, overflow: "hidden" }}>
                <span
                  style={{ fontWeight: 500, color: "var(--io-text-primary)" }}
                >
                  {pt.display_name ?? pt.tagname}
                </span>
                <span
                  style={{
                    color: "var(--io-text-muted)",
                    marginLeft: 6,
                    fontSize: 11,
                    fontFamily: "monospace",
                  }}
                >
                  {pt.tagname}
                </span>
              </span>
              {pt.unit && (
                <span style={{ color: "var(--io-text-muted)", fontSize: 11 }}>
                  {pt.unit}
                </span>
              )}
            </label>
          );
        })}
        {data?.length === 0 && !isFetching && (
          <div
            style={{
              fontSize: 12,
              color: "var(--io-text-muted)",
              textAlign: "center",
              padding: 12,
            }}
          >
            No points found
          </div>
        )}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// PaneConfigModal
// ---------------------------------------------------------------------------

export default function PaneConfigModal({
  pane,
  onSave,
  onClose,
}: PaneConfigModalProps) {
  const [type, setType] = useState<PaneType>(pane.type);
  const [title, setTitle] = useState(pane.title ?? "");
  const [trendPointIds, setTrendPointIds] = useState<string[]>(
    pane.trendPointIds ?? [],
  );
  const [trendDuration, setTrendDuration] = useState(pane.trendDuration ?? 60);
  const [tablePointIds, setTablePointIds] = useState<string[]>(
    pane.tablePointIds ?? [],
  );
  const [alarmFilter, setAlarmFilter] = useState<
    "all" | "active" | "unacknowledged"
  >(pane.alarmFilter ?? "all");

  const handleSave = () => {
    const updated: PaneConfig = {
      id: pane.id,
      type,
      title: title.trim() || undefined,
      trendPointIds: type === "trend" ? trendPointIds : undefined,
      trendDuration: type === "trend" ? trendDuration : undefined,
      tablePointIds: type === "point_table" ? tablePointIds : undefined,
      alarmFilter: type === "alarm_list" ? alarmFilter : undefined,
    };
    onSave(updated);
  };

  return (
    <Dialog.Root open onOpenChange={(open) => !open && onClose()}>
      <Dialog.Portal>
        <Dialog.Overlay
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.55)",
            zIndex: 1000,
          }}
        />
        <Dialog.Content
          aria-describedby={undefined}
          style={{
            position: "fixed",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            zIndex: 1001,
            background: "var(--io-surface)",
            border: "1px solid var(--io-border)",
            borderRadius: 8,
            padding: 24,
            width: 480,
            maxWidth: "calc(100vw - 32px)",
            maxHeight: "calc(100vh - 64px)",
            overflowY: "auto",
            display: "flex",
            flexDirection: "column",
            gap: 20,
          }}
        >
          <Dialog.Title
            style={{
              margin: 0,
              fontSize: 16,
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            Configure Pane
          </Dialog.Title>

          {/* Type selector */}
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <label
              style={{
                fontSize: 12,
                fontWeight: 600,
                color: "var(--io-text-muted)",
                textTransform: "uppercase",
                letterSpacing: "0.04em",
              }}
            >
              Pane Type
            </label>
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
              {PANE_TYPES.map((pt) => (
                <button
                  key={pt.value}
                  onClick={() => setType(pt.value)}
                  style={{
                    padding: "6px 14px",
                    borderRadius: 6,
                    border: `1px solid ${type === pt.value ? "var(--io-accent)" : "var(--io-border)"}`,
                    background:
                      type === pt.value
                        ? "var(--io-accent-subtle, rgba(74,158,255,0.1))"
                        : "var(--io-surface-secondary)",
                    color:
                      type === pt.value
                        ? "var(--io-accent)"
                        : "var(--io-text-primary)",
                    cursor: "pointer",
                    fontSize: 13,
                    fontWeight: type === pt.value ? 600 : 400,
                  }}
                >
                  {pt.label}
                </button>
              ))}
            </div>
          </div>

          {/* Title */}
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            <label
              style={{
                fontSize: 12,
                fontWeight: 600,
                color: "var(--io-text-muted)",
                textTransform: "uppercase",
                letterSpacing: "0.04em",
              }}
            >
              Title (optional)
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder={`e.g. ${PANE_TYPES.find((p) => p.value === type)?.label ?? type}`}
              style={{
                background: "var(--io-surface-secondary)",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
                padding: "7px 10px",
                fontSize: 13,
                color: "var(--io-text-primary)",
                outline: "none",
              }}
            />
          </div>

          {/* Type-specific config */}

          {type === "trend" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                <label
                  style={{
                    fontSize: 12,
                    fontWeight: 600,
                    color: "var(--io-text-muted)",
                    textTransform: "uppercase",
                    letterSpacing: "0.04em",
                  }}
                >
                  Points (max 8)
                </label>
                <PointSearch
                  selected={trendPointIds}
                  onChange={setTrendPointIds}
                  maxSelect={8}
                />
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                <label
                  style={{
                    fontSize: 12,
                    fontWeight: 600,
                    color: "var(--io-text-muted)",
                    textTransform: "uppercase",
                    letterSpacing: "0.04em",
                  }}
                >
                  Duration (minutes)
                </label>
                <select
                  value={trendDuration}
                  onChange={(e) => setTrendDuration(Number(e.target.value))}
                  style={{
                    background: "var(--io-surface-secondary)",
                    border: "1px solid var(--io-border)",
                    borderRadius: 6,
                    padding: "7px 10px",
                    fontSize: 13,
                    color: "var(--io-text-primary)",
                    cursor: "pointer",
                    outline: "none",
                  }}
                >
                  <option value={15}>15 minutes</option>
                  <option value={30}>30 minutes</option>
                  <option value={60}>1 hour</option>
                  <option value={120}>2 hours</option>
                  <option value={240}>4 hours</option>
                  <option value={480}>8 hours</option>
                </select>
              </div>
            </div>
          )}

          {type === "point_table" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              <label
                style={{
                  fontSize: 12,
                  fontWeight: 600,
                  color: "var(--io-text-muted)",
                  textTransform: "uppercase",
                  letterSpacing: "0.04em",
                }}
              >
                Points
              </label>
              <PointSearch
                selected={tablePointIds}
                onChange={setTablePointIds}
              />
            </div>
          )}

          {type === "alarm_list" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              <label
                style={{
                  fontSize: 12,
                  fontWeight: 600,
                  color: "var(--io-text-muted)",
                  textTransform: "uppercase",
                  letterSpacing: "0.04em",
                }}
              >
                Filter
              </label>
              <div style={{ display: "flex", gap: 8 }}>
                {(["all", "active", "unacknowledged"] as const).map((f) => (
                  <label
                    key={f}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 6,
                      cursor: "pointer",
                      fontSize: 13,
                    }}
                  >
                    <input
                      type="radio"
                      name="alarm-filter"
                      value={f}
                      checked={alarmFilter === f}
                      onChange={() => setAlarmFilter(f)}
                      style={{ accentColor: "var(--io-accent)" }}
                    />
                    <span
                      style={{
                        color: "var(--io-text-primary)",
                        textTransform: "capitalize",
                      }}
                    >
                      {f === "unacknowledged"
                        ? "Unacknowledged"
                        : f.charAt(0).toUpperCase() + f.slice(1)}
                    </span>
                  </label>
                ))}
              </div>
            </div>
          )}

          {/* Actions */}
          <div
            style={{
              display: "flex",
              gap: 8,
              justifyContent: "flex-end",
              marginTop: 4,
            }}
          >
            <Dialog.Close asChild>
              <button
                onClick={onClose}
                style={{
                  background: "transparent",
                  border: "1px solid var(--io-border)",
                  borderRadius: 6,
                  padding: "7px 16px",
                  cursor: "pointer",
                  fontSize: 13,
                  color: "var(--io-text-primary)",
                }}
              >
                Cancel
              </button>
            </Dialog.Close>
            <button
              onClick={handleSave}
              style={{
                background: "var(--io-accent)",
                border: "none",
                borderRadius: 6,
                padding: "7px 16px",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 600,
                color: "#fff",
              }}
            >
              Save
            </button>
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

