163	// ---------------------------------------------------------------------------
164	// PaneWrapper
165	// ---------------------------------------------------------------------------
166	
167	export default function PaneWrapper({
168	  config,
169	  locked = false,
170	  isSelected = false,
171	  isFullscreen = false,
172	  onToggleFullscreen,
173	  onConfigure,
174	  onRemove,
175	  onSelect,
176	  onPaletteDrop,
177	  preserveAspectRatio = true,
178	  onCopy: _onCopy,
179	  onDuplicate,
180	  onZoomToFit,
181	  onResetZoom,
182	  onSwapWith,
183	  swapModeSourceId,
184	  onSwapComplete,
185	  onReplace,
186	  onPinToggle,
187	  workspaceId,
188	  hideTitles = false,
189	  onWorkspaceContextMenu,
190	}: PaneWrapperProps) {
191	  const navigate = useNavigate();
192	  const canExportGraphic = usePermission("designer:export");
193	  const title = config.title ?? PANE_TYPE_LABELS[config.type] ?? config.type;
194	  const { pasteDefault, pasteAs } = usePasteEngine();
195	  const clipboardCurrent = useIOClipboardStore((s) => s.current);
196	  const setActiveZone = useGlobalSelectionStore((s) => s.setActiveZone);
197	  const paneZoneId = `console/pane/${config.id}` as SelectionZoneId;
198	  const pasteTarget = findTargetForZone(paneZoneId);
199	  const availableModes =
200	    pasteTarget && clipboardCurrent
201	      ? pasteTarget.accepts(clipboardCurrent)
202	      : [];
203	  const containerRef = useRef<HTMLDivElement>(null);
204	  const [paneCtxMenu, setPaneCtxMenu] = useState<{
205	    x: number;
206	    y: number;
207	  } | null>(null);
208	  const [replaceDialogOpen, setReplaceDialogOpen] = useState(false);
209	  const [replaceSearch, setReplaceSearch] = useState("");
210	  const [dragOver, setDragOver] = useState(false);
211	  const [hovered, setHovered] = useState(false);
212	  const [isBrowserFullscreen, setIsBrowserFullscreen] = useState(false);
213	
214	  useEffect(() => {
215	    function onFSChange() {
216	      setIsBrowserFullscreen(
217	        document.fullscreenElement === containerRef.current,
218	      );
219	    }
220	    document.addEventListener("fullscreenchange", onFSChange);
221	    return () => document.removeEventListener("fullscreenchange", onFSChange);
222	  }, []);
223	
224	  function handleBrowserFullscreen(e: React.MouseEvent) {
225	    e.stopPropagation();
226	    if (isBrowserFullscreen) {
227	      document.exitFullscreen();
228	    } else {
229	      containerRef.current?.requestFullscreen();
230	    }
231	  }
232	
233	  // Fill-workspace and browser fullscreen are mutually exclusive. If browser
234	  // fullscreen is active when fill-workspace is toggled, exit it first so the
235	  // portal PaneWrapper instance starts clean (it won't inherit this state).
236	  function handleToggleMaximize(e?: React.MouseEvent) {
237	    e?.stopPropagation();
238	    if (isBrowserFullscreen) document.exitFullscreen();
239	    onToggleFullscreen?.();
240	  }
241	
242	  const showAllUsers = useAdminToggleStore((s) => s.showAllUsersObjects);
243	
244	  const { data: replaceGraphics = [] } = useQuery({
245	    queryKey: ["console-replace-graphics", showAllUsers],
246	    queryFn: async () => {
247	      const r = await graphicsApi.list({ scope: "console", includeAllUsers: showAllUsers });
248	      if (!r.success) return [];
249	      return r.data.data ?? [];
250	    },
251	    enabled: replaceDialogOpen,
252	    staleTime: 30_000,
253	  });
254	
255	  function handleDragOver(e: React.DragEvent) {
256	    if (e.dataTransfer.types.includes(CONSOLE_DRAG_KEY)) {
257	      e.preventDefault();
258	      e.dataTransfer.dropEffect = "copy";
259	      setDragOver(true);
260	    }
261	  }
262	
263	  function handleDragLeave(e: React.DragEvent) {
264	    // Only clear if leaving the pane itself, not a child
265	    if (!e.currentTarget.contains(e.relatedTarget as Node)) {
266	      setDragOver(false);
267	    }
268	  }
269	
270	  function handleDrop(e: React.DragEvent) {
271	    setDragOver(false);
272	    const raw = e.dataTransfer.getData(CONSOLE_DRAG_KEY);
273	    if (!raw) return;
274	    try {
275	      const item = JSON.parse(raw) as ConsoleDragItem;
276	      onPaletteDrop?.(config.id, item);
277	    } catch {
278	      // ignore malformed
279	    }
280	  }
281	
282	  const isSwapSource = swapModeSourceId === config.id;
283	  const isSwapTarget =
284	    swapModeSourceId != null && swapModeSourceId !== config.id;
285	
286	  function handlePaneClick(e: React.MouseEvent) {
287	    // If swap mode is active and this is a valid target, complete the swap
288	    if (isSwapTarget) {
289	      onSwapComplete?.(config.id);
290	      return;
291	    }
292	    // Ignore clicks on buttons / context menus
