1	import { useState, useCallback, useMemo } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { api } from "../../../api/client";
4	import { useWebSocket } from "../../../shared/hooks/useWebSocket";
5	import type { PaneConfig } from "../types";
6	import { useSelectableItem } from "../../../shared/clipboard";
7	import type { SelectionZoneId } from "../../../shared/clipboard";
8	
9	// ─── Types ──────────────────────────────────────────────────────────────────
10	
11	interface AlarmRow {
12	  id: string;
13	  priority: "urgent" | "high" | "low" | "diagnostic";
14	  tag: string;
15	  message: string;
16	  time: string;
17	  state: "active" | "unacknowledged" | "acknowledged";
18	}
19	
20	interface ApiAlarm {
21	  id: string;
22	  title: string;
23	  severity: "urgent" | "high" | "low" | "diagnostic" | "info";
24	  source: string;
25	  state: string;
26	  triggered_at: string;
27	  acknowledged_at?: string | null;
28	  tag?: string;
29	  message?: string;
30	}
31	
32	// ─── Colors / labels ────────────────────────────────────────────────────────
33	
34	const PRIORITY_COLOR: Record<AlarmRow["priority"], string> = {
35	  urgent: "#EF4444",
36	  high: "#F97316",
37	  low: "#EAB308",
38	  diagnostic: "#F4F4F5",
39	};
40	
41	const PRIORITY_LABEL: Record<AlarmRow["priority"], string> = {
42	  urgent: "URGNT",
43	  high: "HIGH",
44	  low: "LOW",
45	  diagnostic: "DIAG",
46	};
47	
48	function PriorityBadge({ priority }: { priority: AlarmRow["priority"] }) {
49	  return (
50	    <span
51	      style={{
52	        display: "inline-block",
53	        padding: "1px 6px",
54	        borderRadius: 4,
55	        fontSize: 10,
56	        fontWeight: 700,
57	        letterSpacing: "0.05em",
58	        background: `${PRIORITY_COLOR[priority]}22`,
59	        color: PRIORITY_COLOR[priority],
60	        border: `1px solid ${PRIORITY_COLOR[priority]}44`,
61	      }}
62	    >
63	      {PRIORITY_LABEL[priority]}
64	    </span>
65	  );
66	}
67	
68	function StateBadge({ state }: { state: AlarmRow["state"] }) {
69	  const color =
70	    state === "active"
71	      ? "#EF4444"
72	      : state === "unacknowledged"
73	        ? "#F59E0B"
74	        : "var(--io-text-muted)";
75	
76	  return (
77	    <span
78	      style={{
79	        fontSize: 12,
80	        color,
81	        fontWeight: state !== "acknowledged" ? 600 : 400,
82	      }}
83	    >
84	      {state === "active"
85	        ? "Active"
86	        : state === "unacknowledged"
87	          ? "Unack"
88	          : "Acked"}
89	    </span>
90	  );
91	}
92	
93	// ─── Selectable row sub-component ───────────────────────────────────────────
94	
95	function AlarmRowItem({
96	  alarm,
97	  paneZoneId,
98	  onAcknowledge,
99	  isPending,
100	}: {
101	  alarm: AlarmRow;
102	  paneZoneId: SelectionZoneId;
103	  onAcknowledge: (id: string, e: React.MouseEvent) => void;
104	  isPending: boolean;
105	}) {
106	  const entity = useMemo(
107	    () => ({
108	      id: alarm.id,
109	      zoneId: paneZoneId,
110	      kind: "alarm-row" as const,
111	      payload: {
112	        tagname: alarm.tag,
113	        severity: alarm.priority,
114	        title: alarm.message,
115	      },
116	    }),
117	    [alarm.id, alarm.tag, alarm.priority, alarm.message, paneZoneId],
118	  );
119	
120	  const { onMouseDown, isSelected } = useSelectableItem({
121	    zoneId: paneZoneId,
122	    entity,
123	    interactive: true,
124	    onInteractiveClick: () => {},
125	  });
126	
127	  return (
128	    <div
129	      onMouseDown={onMouseDown}
130	      style={{
131	        display: "grid",
132	        gridTemplateColumns: "60px 90px 1fr 80px 90px 70px",
133	        padding: "0 10px",
134	        height: 38,
135	        alignItems: "center",
136	        borderBottom: "1px solid var(--io-border)",
137	        fontSize: 12,
138	        color: "var(--io-text-primary)",
139	        background: isSelected
140	          ? "var(--io-accent-subtle)"
141	          : alarm.state === "active"
142	            ? "rgba(239,68,68,0.04)"
143	            : "transparent",
144	        outline: isSelected ? "1px solid var(--io-accent)" : undefined,
145	        cursor: "default",
146	      }}
147	    >
148	      <span>
149	        <PriorityBadge priority={alarm.priority} />
150	      </span>
151	      <span style={{ fontFamily: "monospace", fontSize: 12 }}>{alarm.tag}</span>
152	      <span
153	        style={{
154	          overflow: "hidden",
155	          textOverflow: "ellipsis",
156	          whiteSpace: "nowrap",
157	          paddingRight: 8,
158	        }}
159	      >
160	        {alarm.message}
161	      </span>
162	      <span
