262	interface AccordionSectionProps {
263	  title: string;
264	  open: boolean;
265	  onToggle: () => void;
266	  badge?: number;
267	  /** Render function receives the current search term (empty string when no search active). */
268	  children: (search: string) => React.ReactNode;
269	  viewMode?: SectionViewMode;
270	  onViewModeChange?: (mode: SectionViewMode) => void;
271	  /** Controlled height for the content area when open; undefined = natural height */
272	  sectionHeight?: number;
273	  /** Called on mousedown of the bottom resize handle */
274	  onHeightResizeMouseDown?: (e: React.MouseEvent) => void;
275	  /** Whether a height resize is currently in progress */
276	  isHeightResizing?: boolean;
277	  /**
278	   * When true and open, the section grows to fill available flex space instead
279	   * of using a fixed pixel height. The content area scrolls internally.
280	   * Flexible sections do not show the bottom resize handle.
281	   */
282	  flexible?: boolean;
283	  /** Show a search toggle icon in the header. Click to reveal/hide an inline search bar. */
284	  searchable?: boolean;
