286	
287	function AccordionSection({
288	  title,
289	  open,
290	  onToggle,
291	  badge,
292	  children,
293	  viewMode,
294	  onViewModeChange,
295	  sectionHeight,
296	  onHeightResizeMouseDown,
297	  isHeightResizing,
298	  flexible,
299	  searchable,
300	}: AccordionSectionProps) {
301	  const [searchActive, setSearchActive] = React.useState(false);
302	  const [searchTerm, setSearchTerm] = React.useState("");
303	  const searchInputRef = React.useRef<HTMLInputElement>(null);
304	
305	  function toggleSearch(e: React.MouseEvent) {
306	    e.stopPropagation();
307	    if (searchActive) {
308	      setSearchActive(false);
309	      setSearchTerm("");
310	    } else {
311	      setSearchActive(true);
312	      setTimeout(() => searchInputRef.current?.focus(), 0);
313	    }
314	  }
315	
316	  return (
317	    <div
318	      style={{
319	        display: "flex",
320	        flexDirection: "column",
321	        ...(flexible && open
322	          ? { flex: "1 1 0", minHeight: 80, overflow: "hidden" }
323	          : { flexShrink: 0 }),
324	      }}
325	    >
326	      <div
327	        style={{ ...sectionHeader, paddingRight: 4 }}
328	        onClick={onToggle}
329	        role="button"
330	        tabIndex={0}
331	        onKeyDown={(e) => {
332	          if (e.key === "Enter" || e.key === " ") onToggle();
333	        }}
334	      >
335	        <svg
336	          style={chevron(open)}
337	          viewBox="0 0 16 16"
338	          fill="none"
339	          stroke="currentColor"
340	          strokeWidth="2"
341	        >
342	          <polyline points="6 4 10 8 6 12" />
343	        </svg>
344	        <span style={sectionLabel}>{title}</span>
345	        {badge !== undefined && badge > 0 && (
346	          <span
347	            style={{
348	              fontSize: 10,
