363	        {searchable && (
364	          <button
365	            title={searchActive ? "Close search" : "Search"}
366	            onClick={toggleSearch}
367	            style={{
368	              background: searchActive ? "var(--io-accent-subtle)" : "none",
369	              border: "none",
370	              cursor: "pointer",
