378	            }}
379	          >
380	            <svg
381	              width="12"
382	              height="12"
383	              viewBox="0 0 24 24"
384	              fill="none"
385	              stroke="currentColor"
386	              strokeWidth="2"
387	              strokeLinecap="round"
388	              strokeLinejoin="round"
389	            >
390	              <circle cx="11" cy="11" r="8" />
391	              <path d="m21 21-4.35-4.35" />
392	            </svg>
393	          </button>
394	        )}
395	      </div>
396	      {open && searchActive && (
397	        <div
398	          style={{
399	            padding: "4px 8px",
400	            borderBottom: "1px solid var(--io-border)",
401	            flexShrink: 0,
402	          }}
403	        >
404	          <input
405	            ref={searchInputRef}
406	            type="search"
407	            placeholder={`Search ${title.toLowerCase()}…`}
408	            value={searchTerm}
409	            onChange={(e) => setSearchTerm(e.target.value)}
410	            onClick={(e) => e.stopPropagation()}
411	            style={{
412	              width: "100%",
413	              padding: "3px 7px",
414	              background: "var(--io-surface-elevated)",
415	              border: "1px solid var(--io-border)",
416	              borderRadius: 4,
417	              color: "var(--io-text)",
418	              fontSize: 11,
419	              outline: "none",
420	              boxSizing: "border-box",
421	            }}
422	          />
423	        </div>
424	      )}
425	      {open && (
426	        <div
427	          style={{
428	            display: "flex",
429	            flexDirection: "column",
430	            ...(flexible
431	              ? { flex: 1, overflow: "hidden" }
432	              : {
433	                  overflow: sectionHeight !== undefined ? "hidden" : undefined,
434	                  height: sectionHeight,
435	                  minHeight:
436	                    sectionHeight !== undefined ? sectionHeight : undefined,
437	                }),
438	          }}
439	        >
440	          <div
441	            style={{
442	              flex: 1,
443	              overflowY:
444	                flexible || sectionHeight !== undefined ? "auto" : undefined,
445	            }}
446	          >
447	            {children(searchActive ? searchTerm : "")}
448	          </div>
449	          {/* Bottom edge resize handle — only for non-flexible sections */}
450	          {!flexible && (
451	            <div
452	              role="separator"
453	              aria-label={`Resize ${title} section height`}
454	              onMouseDown={onHeightResizeMouseDown}
455	              style={{
456	                height: 5,
457	                cursor: "ns-resize",
458	                flexShrink: 0,
459	                background: isHeightResizing
460	                  ? "var(--io-accent)"
461	                  : "transparent",
462	                borderTop: "1px solid var(--io-border)",
463	                transition: "background 0.1s",
464	                userSelect: "none",
465	              }}
466	              onMouseEnter={(e) => {
467	                if (!isHeightResizing) {
468	                  (e.currentTarget as HTMLElement).style.background =
469	                    "var(--io-surface-elevated)";
470	                }
471	              }}
472	              onMouseLeave={(e) => {
473	                if (!isHeightResizing) {
474	                  (e.currentTarget as HTMLElement).style.background =
475	                    "transparent";
476	                }
477	              }}
478	            />
479	          )}
480	        </div>
481	      )}
482	    </div>
483	  );
484	}
