import {
  useCallback,
  useEffect,
  useRef,
  useState,
  lazy,
  Suspense,
} from "react";
import ContextMenu from "../../../shared/components/ContextMenu";
import { useQuery } from "@tanstack/react-query";
import { wsManager } from "../../../shared/hooks/useWebSocket";
import { usePlaybackStore } from "../../../store/playback";
import TimeSeriesChart, {
  type Series,
} from "../../../shared/components/charts/TimeSeriesChart";
import ChartToolbar, {
  INSTANT_READOUT_CHART_TYPES,
} from "../../../shared/components/charts/ChartToolbar";
import { pointsApi } from "../../../api/points";
import type { PaneConfig } from "../types";
import type {
  AggregateType,
  ChartConfig,
} from "../../../shared/components/charts/chart-config-types";
import {
  CHART_AGGREGATE_TYPES,
  defaultBucketSeconds,
} from "../../../shared/components/charts/chart-aggregate-config";
import { useWorkspaceStore } from "../../../store/workspaceStore";
import { useSavedChartsStore } from "../../../store/savedChartsStore";
import { usePermission } from "../../../shared/hooks/usePermission";
import SaveChartModal from "../../../shared/components/charts/SaveChartModal";
import { useSelectionZone } from "../../../store/useSelectionZone";
import { useSelectableItem, usePasteTarget } from "../../../shared/clipboard";
import { useMemo } from "react";
import { createConsolePaneTarget } from "../clipboard/consolePasteTarget";

const ChartConfigPanel = lazy(
  () => import("../../../shared/components/charts/ChartConfigPanel"),
);
const ChartRenderer = lazy(
  () => import("../../../shared/components/charts/ChartRenderer"),
);

// Pre-defined series color palette
const SERIES_COLORS = [
  "#4A9EFF",
  "#F59E0B",
  "#10B981",
  "#EF4444",
  "#8B5CF6",
  "#EC4899",
  "#06B6D4",
  "#84CC16",
];

interface RingBuffer {
  ts: number;
  v: number;
}

// ─── Module-level buffer store ───────────────────────────────────────────────
// Stored outside React so buffers survive component remounts (full-screen
// toggle, navigating away and back). Keyed by pane config ID.
const _paneBuffers = new Map<string, Map<string, RingBuffer[]>>();
const _paneLastTs = new Map<string, Map<string, number>>();

function getPaneBuffers(id: string): Map<string, RingBuffer[]> {
  let m = _paneBuffers.get(id);
  if (!m) {
    m = new Map();
    _paneBuffers.set(id, m);
  }
  return m;
}
function getPaneLastTs(id: string): Map<string, number> {
  let m = _paneLastTs.get(id);
  if (!m) {
    m = new Map();
    _paneLastTs.set(id, m);
  }
  return m;
}

function seedLimit(minutes: number): number {
  if (minutes <= 120) return 7_500;
  if (minutes <= 10080) return 2_500;
  return 2_000;
}

function maxBuffer(durationMinutes: number): number {
  return Math.max(3_600, durationMinutes * 60);
}

interface TrendPaneProps {
  config: PaneConfig;
  editMode: boolean;
  onConfigurePoints?: (paneId: string) => void;
}

// ---------------------------------------------------------------------------
// Hook — fetches metadata for a set of point IDs (aggressively cached)
// ---------------------------------------------------------------------------

interface PointMeta {
  name: string;
  description: string | null;
  unit: string | null;
  source: string;
  /** OPC UA MinimumSamplingInterval in ms. ≥5000 → step/hold-last-value rendering. */
  minimum_sampling_interval_ms: number | null;
}

function usePointMeta(pointIds: string[]) {
  return useQuery({
    queryKey: ["point-meta-batch", pointIds.join(",")],
    queryFn: async () => {
      const results = await Promise.all(
        pointIds.map((id) => pointsApi.getMeta(id)),
      );
      const map = new Map<string, PointMeta>();
      results.forEach((r, idx) => {
        if (r.success) {
          map.set(pointIds[idx], {
            name: r.data.name,
            description: r.data.description,
            unit: r.data.engineering_unit,
            source: r.data.source_name,
            minimum_sampling_interval_ms:
              r.data.minimum_sampling_interval_ms ?? null,
          });
        } else {
          map.set(pointIds[idx], {
            name: pointIds[idx],
            description: null,
            unit: null,
            source: "",
            minimum_sampling_interval_ms: null,
          });
        }
      });
      return map;
    },
    enabled: pointIds.length > 0,
    staleTime: Infinity,
    gcTime: Infinity,
  });
}

// ---------------------------------------------------------------------------
// TrendPane
// ---------------------------------------------------------------------------
// LegendItem — selectable series row in the chart legend
// ---------------------------------------------------------------------------

interface LegendItemProps {
  pointId: string;
  paneId: string;
  label: string;
  color: string;
  isActive: boolean;
  isHighlighted: boolean;
  meta: PointMeta | undefined;
  onToggleHighlight: (label: string, multi: boolean) => void;
  onHoverEnter: (e: React.MouseEvent, meta: PointMeta) => void;
  onHoverLeave: () => void;
}

function LegendItem({
  pointId,
  paneId,
  label,
  color,
  isActive,
  isHighlighted,
  meta,
  onToggleHighlight,
  onHoverEnter,
  onHoverLeave,
}: LegendItemProps) {
  const zoneId = `console/pane/${paneId}` as const;
  const entity = useMemo(
    () => ({
      id: pointId,
      zoneId,
      kind: "chart-series-row" as const,
      payload: {
        tagname: pointId,
        displayName: meta?.name,
        unit: meta?.unit ?? undefined,
      },
    }),
    [pointId, zoneId, meta],
  );
  const { onMouseDown, isSelected } = useSelectableItem({
    zoneId,
    entity,
    interactive: true,
    onInteractiveClick: (e) => onToggleHighlight(label, e.ctrlKey || e.metaKey),
  });

  return (
    <div
      onMouseDown={onMouseDown}
      onMouseEnter={(e) => {
        if (meta) onHoverEnter(e, meta);
      }}
      onMouseLeave={onHoverLeave}
      style={{
        display: "flex",
        alignItems: "center",
        gap: 5,
        fontSize: 11,
        cursor: "pointer",
        userSelect: "none",
        opacity: isActive ? 1 : 0.35,
        transition: "opacity 0.15s",
        outline: isSelected ? "2px solid var(--io-accent)" : undefined,
        outlineOffset: isSelected ? "2px" : undefined,
        borderRadius: 3,
      }}
    >
      <span
        style={{
          display: "inline-block",
          width: 10,
          height: 3,
          borderRadius: 2,
          background: color,
        }}
      />
      <span
        style={{
          color: "var(--io-text-muted)",
          fontWeight: isHighlighted ? 700 : 400,
        }}
      >
        {label}
      </span>
    </div>
  );
}

// ---------------------------------------------------------------------------

export default function TrendPane({
