  useEffect(() => {
    const cutoff = Date.now() / 1000 - durationMinutes * 60;
    let changed = false;
    buffers.current.forEach((buf, id) => {
      const trimmed = buf.filter((e) => e.ts >= cutoff);
      if (trimmed.length < buf.length) {
